var VERSES_JOB=[{"ref":"Job 1:1","short":"Job 1:1","text":"There was a man in the land of Uz whose name was Job, and that man was blameless and upright, one who feared God and turned away from evil.","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":1},{"ref":"Job 1:2","short":"Job 1:2","text":"There were born to him seven sons and three daughters.","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":2},{"ref":"Job 1:3","short":"Job 1:3","text":"He possessed 7,000 sheep, 3,000 camels, 500 yoke of oxen, and 500 female donkeys, and very many servants, so that this man was the greatest of all the people of the east.","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":3},{"ref":"Job 1:4","short":"Job 1:4","text":"His sons used to go and hold a feast in the house of each one on his day, and they would send and invite their three sisters to eat and drink with them.","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":4},{"ref":"Job 1:5","short":"Job 1:5","text":"And when the days of the feast had run their course, Job would send and consecrate them, and he would rise early in the morning and offer burnt offerings according to the number of them all. For Job said, \u201cIt may be that my children have sinned, and cursed God in their hearts.\u201d Thus Job did continually.","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":5},{"ref":"Job 1:6","short":"Job 1:6","text":"Now there was a day when the sons of God came to present themselves before the LORD, and Satan also came among them.","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":6},{"ref":"Job 1:7","short":"Job 1:7","text":"The LORD said to Satan, \u201cFrom where have you come?\u201d Satan answered the LORD and said, \u201cFrom going to and fro on the earth, and from walking up and down on it.\u201d","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":7},{"ref":"Job 1:8","short":"Job 1:8","text":"And the LORD said to Satan, \u201cHave you considered my servant Job, that there is none like him on the earth, a blameless and upright man, who fears God and turns away from evil?\u201d","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":8},{"ref":"Job 1:9","short":"Job 1:9","text":"Then Satan answered the LORD and said, \u201cDoes Job fear God for no reason?","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":9},{"ref":"Job 1:10","short":"Job 1:10","text":"Have you not put a hedge around him and his house and all that he has, on every side? You have blessed the work of his hands, and his possessions have increased in the land.","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":10},{"ref":"Job 1:11","short":"Job 1:11","text":"But stretch out your hand and touch all that he has, and he will curse you to your face.\u201d","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":11},{"ref":"Job 1:12","short":"Job 1:12","text":"And the LORD said to Satan, \u201cBehold, all that he has is in your hand. Only against him do not stretch out your hand.\u201d So Satan went out from the presence of the LORD.","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":12},{"ref":"Job 1:13","short":"Job 1:13","text":"Now there was a day when his sons and daughters were eating and drinking wine in their oldest brother\u2019s house,","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":13},{"ref":"Job 1:14","short":"Job 1:14","text":"and there came a messenger to Job and said, \u201cThe oxen were plowing and the donkeys feeding beside them,","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":14},{"ref":"Job 1:15","short":"Job 1:15","text":"and the Sabeans fell upon them and took them and struck down the servants with the edge of the sword, and I alone have escaped to tell you.\u201d","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":15},{"ref":"Job 1:16","short":"Job 1:16","text":"While he was yet speaking, there came another and said, \u201cThe fire of God fell from heaven and burned up the sheep and the servants and consumed them, and I alone have escaped to tell you.\u201d","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":16},{"ref":"Job 1:17","short":"Job 1:17","text":"While he was yet speaking, there came another and said, \u201cThe Chaldeans formed three groups and made a raid on the camels and took them and struck down the servants with the edge of the sword, and I alone have escaped to tell you.\u201d","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":17},{"ref":"Job 1:18","short":"Job 1:18","text":"While he was yet speaking, there came another and said, \u201cYour sons and daughters were eating and drinking wine in their oldest brother\u2019s house,","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":18},{"ref":"Job 1:19","short":"Job 1:19","text":"and behold, a great wind came across the wilderness and struck the four corners of the house, and it fell upon the young people, and they are dead, and I alone have escaped to tell you.\u201d","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":19},{"ref":"Job 1:20","short":"Job 1:20","text":"Then Job arose and tore his robe and shaved his head and fell on the ground and worshiped.","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":20},{"ref":"Job 1:21","short":"Job 1:21","text":"And he said, \u201cNaked I came from my mother\u2019s womb, and naked shall I return. The LORD gave, and the LORD has taken away; blessed be the name of the LORD.\u201d","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":21},{"ref":"Job 1:22","short":"Job 1:22","text":"In all this Job did not sin or charge God with wrong.","url":"ot/job/Job_1.html","book":"Job","ch":1,"v":22},{"ref":"Job 2:1","short":"Job 2:1","text":"Again there was a day when the sons of God came to present themselves before the LORD, and Satan also came among them to present himself before the LORD.","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":1},{"ref":"Job 2:2","short":"Job 2:2","text":"And the LORD said to Satan, \u201cFrom where have you come?\u201d Satan answered the LORD and said, \u201cFrom going to and fro on the earth, and from walking up and down on it.\u201d","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":2},{"ref":"Job 2:3","short":"Job 2:3","text":"And the LORD said to Satan, \u201cHave you considered my servant Job, that there is none like him on the earth, a blameless and upright man, who fears God and turns away from evil? He still holds fast his integrity, although you incited me against him to destroy him without reason.\u201d","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":3},{"ref":"Job 2:4","short":"Job 2:4","text":"Then Satan answered the LORD and said, \u201cSkin for skin! All that a man has he will give for his life.","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":4},{"ref":"Job 2:5","short":"Job 2:5","text":"But stretch out your hand and touch his bone and his flesh, and he will curse you to your face.\u201d","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":5},{"ref":"Job 2:6","short":"Job 2:6","text":"And the LORD said to Satan, \u201cBehold, he is in your hand; only spare his life.\u201d","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":6},{"ref":"Job 2:7","short":"Job 2:7","text":"So Satan went out from the presence of the LORD and struck Job with loathsome sores from the sole of his foot to the crown of his head.","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":7},{"ref":"Job 2:8","short":"Job 2:8","text":"And he took a piece of broken pottery with which to scrape himself while he sat in the ashes.","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":8},{"ref":"Job 2:9","short":"Job 2:9","text":"Then his wife said to him, \u201cDo you still hold fast your integrity? Curse God and die.\u201d","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":9},{"ref":"Job 2:10","short":"Job 2:10","text":"But he said to her, \u201cYou speak as one of the foolish women would speak. Shall we receive good from God, and shall we not receive evil?\u201d In all this Job did not sin with his lips.","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":10},{"ref":"Job 2:11","short":"Job 2:11","text":"Now when Job\u2019s three friends heard of all this evil that had come upon him, they came each from his own place, Eliphaz the Temanite, Bildad the Shuhite, and Zophar the Naamathite. They made an appointment together to come to show him sympathy and comfort him.","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":11},{"ref":"Job 2:12","short":"Job 2:12","text":"And when they saw him from a distance, they did not recognize him. And they raised their voices and wept, and they tore their robes and sprinkled dust on their heads toward heaven.","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":12},{"ref":"Job 2:13","short":"Job 2:13","text":"And they sat with him on the ground seven days and seven nights, and no one spoke a word to him, for they saw that his suffering was very great.","url":"ot/job/Job_2.html","book":"Job","ch":2,"v":13},{"ref":"Job 3:1","short":"Job 3:1","text":"After this Job opened his mouth and cursed the day of his birth.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":1},{"ref":"Job 3:2","short":"Job 3:2","text":"And Job said:","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":2},{"ref":"Job 3:3","short":"Job 3:3","text":"\u201cLet the day perish on which I was born, and the night that said, \u2018A man is conceived.\u2019","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":3},{"ref":"Job 3:4","short":"Job 3:4","text":"Let that day be darkness! May God above not seek it, nor light shine upon it.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":4},{"ref":"Job 3:5","short":"Job 3:5","text":"Let gloom and deep darkness claim it. Let clouds dwell upon it; let the blackness of the day terrify it.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":5},{"ref":"Job 3:6","short":"Job 3:6","text":"That night\u2014let thick darkness seize it! Let it not rejoice among the days of the year; let it not come into the number of the months.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":6},{"ref":"Job 3:7","short":"Job 3:7","text":"Behold, let that night be barren; let no joyful cry enter it.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":7},{"ref":"Job 3:8","short":"Job 3:8","text":"Let those curse it who curse the day, who are ready to rouse up Leviathan.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":8},{"ref":"Job 3:9","short":"Job 3:9","text":"Let the stars of its dawn be dark; let it hope for light, but have none, nor see the eyelids of the morning,","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":9},{"ref":"Job 3:10","short":"Job 3:10","text":"because it did not shut the doors of my mother\u2019s womb, nor hide trouble from my eyes.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":10},{"ref":"Job 3:11","short":"Job 3:11","text":"\u201cWhy did I not die at birth, come out from the womb and expire?","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":11},{"ref":"Job 3:12","short":"Job 3:12","text":"Why did the knees receive me? Or why the breasts, that I should nurse?","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":12},{"ref":"Job 3:13","short":"Job 3:13","text":"For then I would have lain down and been quiet; I would have slept; then I would have been at rest,","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":13},{"ref":"Job 3:14","short":"Job 3:14","text":"with kings and counselors of the earth who rebuilt ruins for themselves,","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":14},{"ref":"Job 3:15","short":"Job 3:15","text":"or with princes who had gold, who filled their houses with silver.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":15},{"ref":"Job 3:16","short":"Job 3:16","text":"Or why was I not as a hidden stillborn child, as infants who never see the light?","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":16},{"ref":"Job 3:17","short":"Job 3:17","text":"There the wicked cease from troubling, and there the weary are at rest.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":17},{"ref":"Job 3:18","short":"Job 3:18","text":"There the prisoners are at ease together; they hear not the voice of the taskmaster.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":18},{"ref":"Job 3:19","short":"Job 3:19","text":"The small and the great are there, and the slave is free from his master.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":19},{"ref":"Job 3:20","short":"Job 3:20","text":"\u201cWhy is light given to him who is in misery, and life to the bitter in soul,","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":20},{"ref":"Job 3:21","short":"Job 3:21","text":"who long for death, but it comes not, and dig for it more than for hidden treasures,","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":21},{"ref":"Job 3:22","short":"Job 3:22","text":"who rejoice exceedingly and are glad when they find the grave?","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":22},{"ref":"Job 3:23","short":"Job 3:23","text":"Why is light given to a man whose way is hidden, whom God has hedged in?","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":23},{"ref":"Job 3:24","short":"Job 3:24","text":"For my sighing comes instead of my bread, and my groanings are poured out like water.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":24},{"ref":"Job 3:25","short":"Job 3:25","text":"For the thing that I fear comes upon me, and what I dread befalls me.","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":25},{"ref":"Job 3:26","short":"Job 3:26","text":"I am not at ease, nor am I quiet; I have no rest, but trouble comes.\u201d","url":"ot/job/Job_3.html","book":"Job","ch":3,"v":26},{"ref":"Job 4:1","short":"Job 4:1","text":"Then Eliphaz the Temanite answered and said:","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":1},{"ref":"Job 4:2","short":"Job 4:2","text":"\u201cIf one ventures a word with you, will you be impatient? Yet who can keep from speaking?","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":2},{"ref":"Job 4:3","short":"Job 4:3","text":"Behold, you have instructed many, and you have strengthened the weak hands.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":3},{"ref":"Job 4:4","short":"Job 4:4","text":"Your words have upheld him who was stumbling, and you have made firm the feeble knees.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":4},{"ref":"Job 4:5","short":"Job 4:5","text":"But now it has come to you, and you are impatient; it touches you, and you are dismayed.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":5},{"ref":"Job 4:6","short":"Job 4:6","text":"Is not your fear of God your confidence, and the integrity of your ways your hope?","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":6},{"ref":"Job 4:7","short":"Job 4:7","text":"\u201cRemember: who that was innocent ever perished? Or where were the upright cut off?","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":7},{"ref":"Job 4:8","short":"Job 4:8","text":"As I have seen, those who plow iniquity and sow trouble reap the same.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":8},{"ref":"Job 4:9","short":"Job 4:9","text":"By the breath of God they perish, and by the blast of his anger they are consumed.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":9},{"ref":"Job 4:10","short":"Job 4:10","text":"The roar of the lion, the voice of the fierce lion, the teeth of the young lions are broken.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":10},{"ref":"Job 4:11","short":"Job 4:11","text":"The strong lion perishes for lack of prey, and the cubs of the lioness are scattered.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":11},{"ref":"Job 4:12","short":"Job 4:12","text":"\u201cNow a word was brought to me stealthily; my ear received the whisper of it.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":12},{"ref":"Job 4:13","short":"Job 4:13","text":"Amid thoughts from visions of the night, when deep sleep falls on men,","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":13},{"ref":"Job 4:14","short":"Job 4:14","text":"dread came upon me, and trembling, which made all my bones shake.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":14},{"ref":"Job 4:15","short":"Job 4:15","text":"A spirit glided past my face; the hair of my flesh stood up.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":15},{"ref":"Job 4:16","short":"Job 4:16","text":"It stood still, but I could not discern its appearance. A form was before my eyes; there was silence, then I heard a voice:","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":16},{"ref":"Job 4:17","short":"Job 4:17","text":"\u2018Can mortal man be in the right before God? Can a man be pure before his Maker?","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":17},{"ref":"Job 4:18","short":"Job 4:18","text":"Even in his servants he puts no trust, and his angels he charges with error;","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":18},{"ref":"Job 4:19","short":"Job 4:19","text":"how much more those who dwell in houses of clay, whose foundation is in the dust, who are crushed like the moth.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":19},{"ref":"Job 4:20","short":"Job 4:20","text":"Between morning and evening they are beaten to pieces; they perish forever without anyone regarding it.","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":20},{"ref":"Job 4:21","short":"Job 4:21","text":"Is not their tent-cord plucked up within them, do they not die, and that without wisdom?\u2019","url":"ot/job/Job_4.html","book":"Job","ch":4,"v":21},{"ref":"Job 5:1","short":"Job 5:1","text":"\u201cCall now; is there anyone who will answer you? To which of the holy ones will you turn?","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":1},{"ref":"Job 5:2","short":"Job 5:2","text":"Surely vexation kills the fool, and jealousy slays the simple.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":2},{"ref":"Job 5:3","short":"Job 5:3","text":"I have seen the fool taking root, but suddenly I cursed his dwelling.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":3},{"ref":"Job 5:4","short":"Job 5:4","text":"His children are far from safety; they are crushed in the gate, and there is no one to deliver them.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":4},{"ref":"Job 5:5","short":"Job 5:5","text":"The hungry eat his harvest, and he takes it even out of thorns, and the thirsty pant after his wealth.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":5},{"ref":"Job 5:6","short":"Job 5:6","text":"For affliction does not come from the dust, nor does trouble sprout from the ground,","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":6},{"ref":"Job 5:7","short":"Job 5:7","text":"but man is born to trouble as the sparks fly upward.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":7},{"ref":"Job 5:8","short":"Job 5:8","text":"\u201cAs for me, I would seek God, and to God would I commit my cause,","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":8},{"ref":"Job 5:9","short":"Job 5:9","text":"who does great things and unsearchable, marvelous things without number:","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":9},{"ref":"Job 5:10","short":"Job 5:10","text":"he gives rain on the earth and sends waters on the fields;","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":10},{"ref":"Job 5:11","short":"Job 5:11","text":"he sets on high those who are lowly, and those who mourn are lifted to safety.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":11},{"ref":"Job 5:12","short":"Job 5:12","text":"He frustrates the devices of the crafty, so that their hands achieve no success.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":12},{"ref":"Job 5:13","short":"Job 5:13","text":"He catches the wise in their own craftiness, and the schemes of the wily are brought to a quick end.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":13},{"ref":"Job 5:14","short":"Job 5:14","text":"They meet with darkness in the daytime and grope at noonday as in the night.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":14},{"ref":"Job 5:15","short":"Job 5:15","text":"But he saves the needy from the sword of their mouth and from the hand of the mighty.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":15},{"ref":"Job 5:16","short":"Job 5:16","text":"So the poor have hope, and injustice shuts her mouth.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":16},{"ref":"Job 5:17","short":"Job 5:17","text":"\u201cBehold, blessed is the one whom God reproves; therefore despise not the discipline of the Almighty.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":17},{"ref":"Job 5:18","short":"Job 5:18","text":"For he wounds, but he binds up; he shatters, but his hands heal.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":18},{"ref":"Job 5:19","short":"Job 5:19","text":"He will deliver you from six troubles; in seven no evil shall touch you.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":19},{"ref":"Job 5:20","short":"Job 5:20","text":"In famine he will redeem you from death, and in war from the power of the sword.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":20},{"ref":"Job 5:21","short":"Job 5:21","text":"You shall be hidden from the lash of the tongue, and shall not fear destruction when it comes.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":21},{"ref":"Job 5:22","short":"Job 5:22","text":"At destruction and famine you shall laugh, and shall not fear the beasts of the earth.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":22},{"ref":"Job 5:23","short":"Job 5:23","text":"For you shall be in league with the stones of the field, and the beasts of the field shall be at peace with you.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":23},{"ref":"Job 5:24","short":"Job 5:24","text":"You shall know that your tent is at peace, and you shall inspect your fold and miss nothing.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":24},{"ref":"Job 5:25","short":"Job 5:25","text":"You shall know also that your offspring shall be many, and your descendants as the grass of the earth.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":25},{"ref":"Job 5:26","short":"Job 5:26","text":"You shall come to your grave in ripe old age, like a sheaf gathered up in its season.","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":26},{"ref":"Job 5:27","short":"Job 5:27","text":"Behold, this we have searched out; it is true. Hear, and know it for your good.\u201d","url":"ot/job/Job_5.html","book":"Job","ch":5,"v":27},{"ref":"Job 6:1","short":"Job 6:1","text":"Then Job answered and said:","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":1},{"ref":"Job 6:2","short":"Job 6:2","text":"\u201cOh that my vexation were weighed, and all my calamity laid in the balances!","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":2},{"ref":"Job 6:3","short":"Job 6:3","text":"For then it would be heavier than the sand of the sea; therefore my words have been rash.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":3},{"ref":"Job 6:4","short":"Job 6:4","text":"For the arrows of the Almighty are in me; my spirit drinks their poison; the terrors of God are arrayed against me.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":4},{"ref":"Job 6:5","short":"Job 6:5","text":"Does the wild donkey bray when he has grass, or the ox low over his fodder?","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":5},{"ref":"Job 6:6","short":"Job 6:6","text":"Can that which is tasteless be eaten without salt, or is there any taste in the juice of the mallow?","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":6},{"ref":"Job 6:7","short":"Job 6:7","text":"My appetite refuses to touch them; they are as food that is loathsome to me.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":7},{"ref":"Job 6:8","short":"Job 6:8","text":"\u201cOh that I might have my request, and that God would fulfill my hope,","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":8},{"ref":"Job 6:9","short":"Job 6:9","text":"that it would please God to crush me, that he would let loose his hand and cut me off!","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":9},{"ref":"Job 6:10","short":"Job 6:10","text":"This would be my comfort; I would even exult in pain unsparing, for I have not denied the words of the Holy One.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":10},{"ref":"Job 6:11","short":"Job 6:11","text":"What is my strength, that I should wait? And what is my end, that I should be patient?","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":11},{"ref":"Job 6:12","short":"Job 6:12","text":"Is my strength the strength of stones, or is my flesh bronze?","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":12},{"ref":"Job 6:13","short":"Job 6:13","text":"Have I any help in me, when resource is driven from me?","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":13},{"ref":"Job 6:14","short":"Job 6:14","text":"\u201cHe who withholds kindness from a friend forsakes the fear of the Almighty.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":14},{"ref":"Job 6:15","short":"Job 6:15","text":"My brothers are treacherous as a torrent-bed, as torrential streams that pass away,","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":15},{"ref":"Job 6:16","short":"Job 6:16","text":"which are dark with ice, and where the snow hides itself.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":16},{"ref":"Job 6:17","short":"Job 6:17","text":"When they melt, they disappear; when it is hot, they vanish from their place.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":17},{"ref":"Job 6:18","short":"Job 6:18","text":"The caravans turn aside from their course; they go up into the waste and perish.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":18},{"ref":"Job 6:19","short":"Job 6:19","text":"The caravans of Tema look, the travelers of Sheba hope.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":19},{"ref":"Job 6:20","short":"Job 6:20","text":"They are ashamed because they were confident; they come there and are disappointed.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":20},{"ref":"Job 6:21","short":"Job 6:21","text":"For you have now become nothing; you see my calamity and are afraid.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":21},{"ref":"Job 6:22","short":"Job 6:22","text":"Have I said, \u2018Make me a gift\u2019? Or, \u2018From your wealth offer a bribe for me\u2019?","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":22},{"ref":"Job 6:23","short":"Job 6:23","text":"Or, \u2018Deliver me from the adversary\u2019s hand\u2019? Or, \u2018Redeem me from the hand of the ruthless\u2019?","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":23},{"ref":"Job 6:24","short":"Job 6:24","text":"\u201cTeach me, and I will be silent; make me understand how I have gone astray.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":24},{"ref":"Job 6:25","short":"Job 6:25","text":"How forceful are upright words! But what does reproof from you reprove?","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":25},{"ref":"Job 6:26","short":"Job 6:26","text":"Do you think that you can reprove words, when the speech of a despairing man is wind?","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":26},{"ref":"Job 6:27","short":"Job 6:27","text":"You would even cast lots over the fatherless, and bargain over your friend.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":27},{"ref":"Job 6:28","short":"Job 6:28","text":"\u201cBut now, be pleased to look at me, for I will not lie to your face.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":28},{"ref":"Job 6:29","short":"Job 6:29","text":"Please turn; let no injustice be done. Turn now; my vindication is at stake.","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":29},{"ref":"Job 6:30","short":"Job 6:30","text":"Is there any injustice on my tongue? Cannot my palate discern the cause of calamity?","url":"ot/job/Job_6.html","book":"Job","ch":6,"v":30},{"ref":"Job 7:1","short":"Job 7:1","text":"\u201cHas not man a hard service on earth, and are not his days like the days of a hired hand?","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":1},{"ref":"Job 7:2","short":"Job 7:2","text":"Like a slave who longs for the shadow, and like a hired hand who looks for his wages,","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":2},{"ref":"Job 7:3","short":"Job 7:3","text":"so I am allotted months of emptiness, and nights of misery are apportioned to me.","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":3},{"ref":"Job 7:4","short":"Job 7:4","text":"When I lie down I say, \u2018When shall I arise?\u2019 But the night is long, and I toss and turn till the dawn.","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":4},{"ref":"Job 7:5","short":"Job 7:5","text":"My flesh is clothed with worms and dirt; my skin hardens, then breaks out afresh.","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":5},{"ref":"Job 7:6","short":"Job 7:6","text":"My days are swifter than a weaver\u2019s shuttle and come to their end without hope.","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":6},{"ref":"Job 7:7","short":"Job 7:7","text":"\u201cRemember that my life is a breath; my eye will never again see good.","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":7},{"ref":"Job 7:8","short":"Job 7:8","text":"The eye of him who sees me will behold me no more; while your eyes are on me, I shall be gone.","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":8},{"ref":"Job 7:9","short":"Job 7:9","text":"As the cloud fades and vanishes, so he who goes down to Sheol does not come up;","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":9},{"ref":"Job 7:10","short":"Job 7:10","text":"he returns no more to his house, nor does his place know him anymore.","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":10},{"ref":"Job 7:11","short":"Job 7:11","text":"\u201cTherefore I will not restrain my mouth; I will speak in the anguish of my spirit; I will complain in the bitterness of my soul.","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":11},{"ref":"Job 7:12","short":"Job 7:12","text":"Am I the sea, or a sea monster, that you set a guard over me?","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":12},{"ref":"Job 7:13","short":"Job 7:13","text":"When I say, \u2018My bed will comfort me, my couch will ease my complaint,\u2019","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":13},{"ref":"Job 7:14","short":"Job 7:14","text":"then you scare me with dreams and terrify me with visions,","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":14},{"ref":"Job 7:15","short":"Job 7:15","text":"so that I would choose strangling and death rather than my bones.","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":15},{"ref":"Job 7:16","short":"Job 7:16","text":"I loathe my life; I would not live forever. Leave me alone, for my days are a breath.","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":16},{"ref":"Job 7:17","short":"Job 7:17","text":"What is man, that you make so much of him, and that you set your heart on him,","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":17},{"ref":"Job 7:18","short":"Job 7:18","text":"visit him every morning and test him every moment?","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":18},{"ref":"Job 7:19","short":"Job 7:19","text":"How long will you not look away from me, nor leave me alone till I swallow my spit?","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":19},{"ref":"Job 7:20","short":"Job 7:20","text":"If I sin, what do I do to you, you watcher of mankind? Why have you made me your mark? Why have I become a burden to you?","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":20},{"ref":"Job 7:21","short":"Job 7:21","text":"Why do you not pardon my transgression and take away my iniquity? For now I shall lie in the earth; you will seek me, but I shall not be.\u201d","url":"ot/job/Job_7.html","book":"Job","ch":7,"v":21},{"ref":"Job 8:1","short":"Job 8:1","text":"Then Bildad the Shuhite answered and said:","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":1},{"ref":"Job 8:2","short":"Job 8:2","text":"\u201cHow long will you say these things, and the words of your mouth be a great wind?","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":2},{"ref":"Job 8:3","short":"Job 8:3","text":"Does God pervert justice? Or does the Almighty pervert the right?","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":3},{"ref":"Job 8:4","short":"Job 8:4","text":"If your children have sinned against him, he has delivered them into the hand of their transgression.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":4},{"ref":"Job 8:5","short":"Job 8:5","text":"If you will seek God and plead with the Almighty for mercy,","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":5},{"ref":"Job 8:6","short":"Job 8:6","text":"if you are pure and upright, surely then he will rouse himself for you and restore your rightful habitation.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":6},{"ref":"Job 8:7","short":"Job 8:7","text":"And though your beginning was small, your latter days will be very great.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":7},{"ref":"Job 8:8","short":"Job 8:8","text":"\u201cFor inquire, please, of bygone ages, and consider what the fathers have searched out.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":8},{"ref":"Job 8:9","short":"Job 8:9","text":"For we are but of yesterday and know nothing, for our days on earth are a shadow.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":9},{"ref":"Job 8:10","short":"Job 8:10","text":"Will they not teach you and tell you and utter words out of their understanding?","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":10},{"ref":"Job 8:11","short":"Job 8:11","text":"\u201cCan papyrus grow where there is no marsh? Can reeds flourish where there is no water?","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":11},{"ref":"Job 8:12","short":"Job 8:12","text":"While yet in flower and not cut down, they wither before any other plant.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":12},{"ref":"Job 8:13","short":"Job 8:13","text":"Such are the paths of all who forget God; the hope of the godless shall perish.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":13},{"ref":"Job 8:14","short":"Job 8:14","text":"His confidence is severed, and his trust is a spider\u2019s web.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":14},{"ref":"Job 8:15","short":"Job 8:15","text":"He leans against his house, but it does not stand; he lays hold of it, but it does not endure.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":15},{"ref":"Job 8:16","short":"Job 8:16","text":"He is a lush plant before the sun, and his shoots spread over his garden.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":16},{"ref":"Job 8:17","short":"Job 8:17","text":"His roots entwine the stone heap; he looks upon a house of stones.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":17},{"ref":"Job 8:18","short":"Job 8:18","text":"If he is destroyed from his place, then it will deny him, saying, \u2018I have never seen you.\u2019","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":18},{"ref":"Job 8:19","short":"Job 8:19","text":"Behold, this is the joy of his way, and out of the soil others will spring.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":19},{"ref":"Job 8:20","short":"Job 8:20","text":"\u201cBehold, God will not reject a blameless man, nor take the hand of evildoers.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":20},{"ref":"Job 8:21","short":"Job 8:21","text":"He will yet fill your mouth with laughter, and your lips with shouting.","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":21},{"ref":"Job 8:22","short":"Job 8:22","text":"Those who hate you will be clothed with shame, and the tent of the wicked will be no more.\u201d","url":"ot/job/Job_8.html","book":"Job","ch":8,"v":22},{"ref":"Job 9:1","short":"Job 9:1","text":"Then Job answered and said:","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":1},{"ref":"Job 9:2","short":"Job 9:2","text":"\u201cTruly I know that it is so: But how can a man be in the right before God?","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":2},{"ref":"Job 9:3","short":"Job 9:3","text":"If one wished to contend with him, one could not answer him once in a thousand times.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":3},{"ref":"Job 9:4","short":"Job 9:4","text":"He is wise in heart and mighty in strength\u2014 who has hardened himself against him, and succeeded?\u2014","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":4},{"ref":"Job 9:5","short":"Job 9:5","text":"he who removes mountains, and they know it not, when he overturns them in his anger,","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":5},{"ref":"Job 9:6","short":"Job 9:6","text":"who shakes the earth out of its place, and its pillars tremble;","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":6},{"ref":"Job 9:7","short":"Job 9:7","text":"who commands the sun, and it does not rise; who seals up the stars;","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":7},{"ref":"Job 9:8","short":"Job 9:8","text":"who alone stretched out the heavens and trampled the waves of the sea;","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":8},{"ref":"Job 9:9","short":"Job 9:9","text":"who made the Bear and Orion, the Pleiades and the chambers of the south;","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":9},{"ref":"Job 9:10","short":"Job 9:10","text":"who does great things beyond searching out, and marvelous things beyond number.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":10},{"ref":"Job 9:11","short":"Job 9:11","text":"Behold, he passes by me, and I see him not; he moves on, but I do not perceive him.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":11},{"ref":"Job 9:12","short":"Job 9:12","text":"Behold, he snatches away; who can turn him back? Who will say to him, \u2018What are you doing?\u2019","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":12},{"ref":"Job 9:13","short":"Job 9:13","text":"\u201cGod will not turn back his anger; beneath him bowed the helpers of Rahab.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":13},{"ref":"Job 9:14","short":"Job 9:14","text":"How then can I answer him, choosing my words with him?","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":14},{"ref":"Job 9:15","short":"Job 9:15","text":"Though I am in the right, I cannot answer him; I must appeal for mercy to my accuser.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":15},{"ref":"Job 9:16","short":"Job 9:16","text":"If I summoned him and he answered me, I would not believe that he was listening to my voice.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":16},{"ref":"Job 9:17","short":"Job 9:17","text":"For he crushes me with a tempest and multiplies my wounds without cause;","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":17},{"ref":"Job 9:18","short":"Job 9:18","text":"he will not let me get my breath, but fills me with bitterness.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":18},{"ref":"Job 9:19","short":"Job 9:19","text":"If it is a contest of strength, behold, he is mighty! If it is a matter of justice, who can summon him?","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":19},{"ref":"Job 9:20","short":"Job 9:20","text":"Though I am in the right, my own mouth would condemn me; though I am blameless, he would prove me perverse.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":20},{"ref":"Job 9:21","short":"Job 9:21","text":"I am blameless; I regard not myself; I loathe my life.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":21},{"ref":"Job 9:22","short":"Job 9:22","text":"It is all one; therefore I say, \u2018He destroys both the blameless and the wicked.\u2019","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":22},{"ref":"Job 9:23","short":"Job 9:23","text":"When disaster brings sudden death, he mocks at the calamity of the innocent.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":23},{"ref":"Job 9:24","short":"Job 9:24","text":"The earth is given into the hand of the wicked; he covers the faces of its judges\u2014 if it is not he, who then is it?","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":24},{"ref":"Job 9:25","short":"Job 9:25","text":"\u201cMy days are swifter than a runner; they flee away; they see no good.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":25},{"ref":"Job 9:26","short":"Job 9:26","text":"They go by like skiffs of reed, like an eagle swooping on the prey.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":26},{"ref":"Job 9:27","short":"Job 9:27","text":"If I say, \u2018I will forget my complaint, I will put off my sad face, and be of good cheer,\u2019","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":27},{"ref":"Job 9:28","short":"Job 9:28","text":"I become afraid of all my suffering, for I know you will not hold me innocent.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":28},{"ref":"Job 9:29","short":"Job 9:29","text":"I shall be condemned; why then do I labor in vain?","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":29},{"ref":"Job 9:30","short":"Job 9:30","text":"If I wash myself with snow and cleanse my hands with lye,","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":30},{"ref":"Job 9:31","short":"Job 9:31","text":"yet you will plunge me into a pit, and my own clothes will abhor me.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":31},{"ref":"Job 9:32","short":"Job 9:32","text":"For he is not a man, as I am, that I might answer him, that we should come to trial together.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":32},{"ref":"Job 9:33","short":"Job 9:33","text":"There is no arbiter between us, who might lay his hand on us both.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":33},{"ref":"Job 9:34","short":"Job 9:34","text":"Let him take his rod away from me, and let not dread of him terrify me.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":34},{"ref":"Job 9:35","short":"Job 9:35","text":"Then I would speak without fear of him, for I am not so in myself.","url":"ot/job/Job_9.html","book":"Job","ch":9,"v":35},{"ref":"Job 10:1","short":"Job 10:1","text":"\u201cI loathe my life; I will give free utterance to my complaint; I will speak in the bitterness of my soul.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":1},{"ref":"Job 10:2","short":"Job 10:2","text":"I will say to God, Do not condemn me; let me know why you contend against me.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":2},{"ref":"Job 10:3","short":"Job 10:3","text":"Does it seem good to you to oppress, to despise the work of your hands and favor the designs of the wicked?","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":3},{"ref":"Job 10:4","short":"Job 10:4","text":"Have you eyes of flesh? Do you see as man sees?","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":4},{"ref":"Job 10:5","short":"Job 10:5","text":"Are your days as the days of man, or your years as a man\u2019s years,","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":5},{"ref":"Job 10:6","short":"Job 10:6","text":"that you seek out my iniquity and search for my sin,","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":6},{"ref":"Job 10:7","short":"Job 10:7","text":"although you know that I am not guilty, and there is none to deliver out of your hand?","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":7},{"ref":"Job 10:8","short":"Job 10:8","text":"Your hands fashioned and made me, and now you have destroyed me altogether.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":8},{"ref":"Job 10:9","short":"Job 10:9","text":"Remember that you have made me like clay; and will you return me to the dust?","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":9},{"ref":"Job 10:10","short":"Job 10:10","text":"Did you not pour me out like milk and curdle me like cheese?","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":10},{"ref":"Job 10:11","short":"Job 10:11","text":"You clothed me with skin and flesh, and knit me together with bones and sinews.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":11},{"ref":"Job 10:12","short":"Job 10:12","text":"You have granted me life and steadfast love, and your care has preserved my spirit.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":12},{"ref":"Job 10:13","short":"Job 10:13","text":"Yet these things you hid in your heart; I know that this was your purpose.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":13},{"ref":"Job 10:14","short":"Job 10:14","text":"If I sin, you watch me and do not acquit me of my iniquity.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":14},{"ref":"Job 10:15","short":"Job 10:15","text":"If I am guilty, woe to me! If I am in the right, I cannot lift up my head, for I am filled with disgrace and look on my affliction.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":15},{"ref":"Job 10:16","short":"Job 10:16","text":"And were my head lifted up, you would hunt me like a lion and again work wonders against me.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":16},{"ref":"Job 10:17","short":"Job 10:17","text":"You renew your witnesses against me and increase your vexation toward me; you bring fresh troops against me.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":17},{"ref":"Job 10:18","short":"Job 10:18","text":"\u201cWhy did you bring me out from the womb? Would that I had died before any eye had seen me","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":18},{"ref":"Job 10:19","short":"Job 10:19","text":"and were as though I had not been, carried from the womb to the grave.","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":19},{"ref":"Job 10:20","short":"Job 10:20","text":"Are not my days few? Then cease, and leave me alone, that I may find a little cheer","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":20},{"ref":"Job 10:21","short":"Job 10:21","text":"before I go\u2014and I shall not return\u2014 to the land of darkness and deep shadow,","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":21},{"ref":"Job 10:22","short":"Job 10:22","text":"the land of gloom like thick darkness, like deep shadow without any order, where light is as thick darkness.\u201d","url":"ot/job/Job_10.html","book":"Job","ch":10,"v":22},{"ref":"Job 11:1","short":"Job 11:1","text":"Then Zophar the Naamathite answered and said:","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":1},{"ref":"Job 11:2","short":"Job 11:2","text":"\u201cShould a multitude of words go unanswered, and a man full of talk be judged right?","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":2},{"ref":"Job 11:3","short":"Job 11:3","text":"Should your babble silence men, and when you mock, shall no one shame you?","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":3},{"ref":"Job 11:4","short":"Job 11:4","text":"For you say, \u2018My doctrine is pure, and I am clean in God\u2019s eyes.\u2019","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":4},{"ref":"Job 11:5","short":"Job 11:5","text":"But oh, that God would speak and open his lips to you,","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":5},{"ref":"Job 11:6","short":"Job 11:6","text":"and that he would tell you the secrets of wisdom! For he is manifold in understanding. Know then that God exacts of you less than your guilt deserves.","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":6},{"ref":"Job 11:7","short":"Job 11:7","text":"\u201cCan you find out the deep things of God? Can you find out the limit of the Almighty?","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":7},{"ref":"Job 11:8","short":"Job 11:8","text":"It is higher than heaven\u2014what can you do? Deeper than Sheol\u2014what can you know?","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":8},{"ref":"Job 11:9","short":"Job 11:9","text":"Its measure is longer than the earth and broader than the sea.","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":9},{"ref":"Job 11:10","short":"Job 11:10","text":"If he passes through and imprisons and summons the court, who can turn him back?","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":10},{"ref":"Job 11:11","short":"Job 11:11","text":"For he knows worthless men; when he sees iniquity, will he not consider it?","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":11},{"ref":"Job 11:12","short":"Job 11:12","text":"But a stupid man will get understanding when a wild donkey\u2019s colt is born a man!","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":12},{"ref":"Job 11:13","short":"Job 11:13","text":"\u201cIf you prepare your heart, you will stretch out your hands toward him.","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":13},{"ref":"Job 11:14","short":"Job 11:14","text":"If iniquity is in your hand, put it far away, and let not injustice dwell in your tents.","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":14},{"ref":"Job 11:15","short":"Job 11:15","text":"Surely then you will lift up your face without blemish; you will be secure and will not fear.","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":15},{"ref":"Job 11:16","short":"Job 11:16","text":"You will forget your misery; you will remember it as waters that have passed away.","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":16},{"ref":"Job 11:17","short":"Job 11:17","text":"And your life will be brighter than the noonday; its darkness will be like the morning.","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":17},{"ref":"Job 11:18","short":"Job 11:18","text":"And you will feel secure, because there is hope; you will look around and take your rest in security.","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":18},{"ref":"Job 11:19","short":"Job 11:19","text":"You will lie down, and none will make you afraid; many will court your favor.","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":19},{"ref":"Job 11:20","short":"Job 11:20","text":"But the eyes of the wicked will fail; all way of escape will be lost to them, and their hope is to breathe their last.\u201d","url":"ot/job/Job_11.html","book":"Job","ch":11,"v":20},{"ref":"Job 12:1","short":"Job 12:1","text":"Then Job answered and said:","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":1},{"ref":"Job 12:2","short":"Job 12:2","text":"\u201cNo doubt you are the people, and wisdom will die with you.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":2},{"ref":"Job 12:3","short":"Job 12:3","text":"But I have understanding as well as you; I am not inferior to you. Who does not know such things as these?","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":3},{"ref":"Job 12:4","short":"Job 12:4","text":"I am a laughingstock to my friends; I, who called to God and he answered me, a just and blameless man, am a laughingstock.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":4},{"ref":"Job 12:5","short":"Job 12:5","text":"In the thought of one who is at ease there is contempt for misfortune; it is ready for those whose feet slip.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":5},{"ref":"Job 12:6","short":"Job 12:6","text":"The tents of robbers are at peace, and those who provoke God are secure, who bring their god in their hand.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":6},{"ref":"Job 12:7","short":"Job 12:7","text":"\u201cBut ask the beasts, and they will teach you; the birds of the heavens, and they will tell you;","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":7},{"ref":"Job 12:8","short":"Job 12:8","text":"or the bushes of the earth, and they will teach you; and the fish of the sea will declare to you.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":8},{"ref":"Job 12:9","short":"Job 12:9","text":"Who among all these does not know that the hand of the LORD has done this?","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":9},{"ref":"Job 12:10","short":"Job 12:10","text":"In his hand is the life of every living thing and the breath of all mankind.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":10},{"ref":"Job 12:11","short":"Job 12:11","text":"Does not the ear test words as the palate tastes food?","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":11},{"ref":"Job 12:12","short":"Job 12:12","text":"Wisdom is with the aged, and understanding in length of days.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":12},{"ref":"Job 12:13","short":"Job 12:13","text":"\u201cWith God are wisdom and might; he has counsel and understanding.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":13},{"ref":"Job 12:14","short":"Job 12:14","text":"If he tears down, none can rebuild; if he shuts a man in, none can open.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":14},{"ref":"Job 12:15","short":"Job 12:15","text":"If he withholds the waters, they dry up; if he sends them out, they overwhelm the land.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":15},{"ref":"Job 12:16","short":"Job 12:16","text":"With him are strength and sound wisdom; the deceived and the deceiver are his.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":16},{"ref":"Job 12:17","short":"Job 12:17","text":"He leads counselors away stripped, and judges he makes fools.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":17},{"ref":"Job 12:18","short":"Job 12:18","text":"He looses the bonds of kings and binds a waistcloth on their hips.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":18},{"ref":"Job 12:19","short":"Job 12:19","text":"He leads priests away stripped and overthrows the mighty.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":19},{"ref":"Job 12:20","short":"Job 12:20","text":"He deprives of speech those who are trusted and takes away the discernment of the elders.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":20},{"ref":"Job 12:21","short":"Job 12:21","text":"He pours contempt on princes and loosens the belt of the strong.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":21},{"ref":"Job 12:22","short":"Job 12:22","text":"He uncovers the deeps out of darkness and brings deep darkness to light.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":22},{"ref":"Job 12:23","short":"Job 12:23","text":"He makes nations great, and he destroys them; he enlarges nations, and leads them away.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":23},{"ref":"Job 12:24","short":"Job 12:24","text":"He takes away understanding from the chiefs of the people of the earth and makes them wander in a trackless waste.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":24},{"ref":"Job 12:25","short":"Job 12:25","text":"They grope in the dark without light, and he makes them stagger like a drunken man.","url":"ot/job/Job_12.html","book":"Job","ch":12,"v":25},{"ref":"Job 13:1","short":"Job 13:1","text":"\u201cBehold, my eye has seen all this, my ear has heard and understood it.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":1},{"ref":"Job 13:2","short":"Job 13:2","text":"What you know, I also know; I am not inferior to you.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":2},{"ref":"Job 13:3","short":"Job 13:3","text":"But I would speak to the Almighty, and I desire to argue my case with God.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":3},{"ref":"Job 13:4","short":"Job 13:4","text":"As for you, you whitewash with lies; worthless physicians are you all.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":4},{"ref":"Job 13:5","short":"Job 13:5","text":"Oh that you would keep silent, and it would be your wisdom!","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":5},{"ref":"Job 13:6","short":"Job 13:6","text":"Hear now my argument and listen to the pleadings of my lips.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":6},{"ref":"Job 13:7","short":"Job 13:7","text":"Will you speak falsely for God and speak deceitfully for him?","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":7},{"ref":"Job 13:8","short":"Job 13:8","text":"Will you show partiality toward him? Will you plead the case for God?","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":8},{"ref":"Job 13:9","short":"Job 13:9","text":"Will it be well with you when he searches you out? Or can you deceive him, as one deceives a man?","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":9},{"ref":"Job 13:10","short":"Job 13:10","text":"He will surely rebuke you if in secret you show partiality.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":10},{"ref":"Job 13:11","short":"Job 13:11","text":"Will not his majesty terrify you, and the dread of him fall upon you?","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":11},{"ref":"Job 13:12","short":"Job 13:12","text":"Your maxims are proverbs of ashes; your defenses are defenses of clay.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":12},{"ref":"Job 13:13","short":"Job 13:13","text":"\u201cLet me have silence, and I will speak, and let come on me what may.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":13},{"ref":"Job 13:14","short":"Job 13:14","text":"Why should I take my flesh in my teeth and put my life in my hand?","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":14},{"ref":"Job 13:15","short":"Job 13:15","text":"Though he slay me, I will hope in him; yet I will argue my ways to his face.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":15},{"ref":"Job 13:16","short":"Job 13:16","text":"This will be my salvation, that the godless shall not come before him.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":16},{"ref":"Job 13:17","short":"Job 13:17","text":"Keep listening to my words, and let my declaration be in your ears.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":17},{"ref":"Job 13:18","short":"Job 13:18","text":"Behold, I have prepared my case; I know that I shall be in the right.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":18},{"ref":"Job 13:19","short":"Job 13:19","text":"Who is there who will contend with me? For then I would be silent and die.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":19},{"ref":"Job 13:20","short":"Job 13:20","text":"Only grant me two things, then I will not hide myself from your face:","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":20},{"ref":"Job 13:21","short":"Job 13:21","text":"withdraw your hand far from me, and let not dread of you terrify me.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":21},{"ref":"Job 13:22","short":"Job 13:22","text":"Then call, and I will answer; or let me speak, and you reply to me.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":22},{"ref":"Job 13:23","short":"Job 13:23","text":"How many are my iniquities and my sins? Make me know my transgression and my sin.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":23},{"ref":"Job 13:24","short":"Job 13:24","text":"Why do you hide your face and count me as your enemy?","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":24},{"ref":"Job 13:25","short":"Job 13:25","text":"Will you frighten a driven leaf and pursue dry chaff?","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":25},{"ref":"Job 13:26","short":"Job 13:26","text":"For you write bitter things against me and make me inherit the iniquities of my youth.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":26},{"ref":"Job 13:27","short":"Job 13:27","text":"You put my feet in the stocks and watch all my paths; you set a limit for the soles of my feet.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":27},{"ref":"Job 13:28","short":"Job 13:28","text":"Man wastes away like a rotten thing, like a garment that is moth-eaten.","url":"ot/job/Job_13.html","book":"Job","ch":13,"v":28},{"ref":"Job 14:1","short":"Job 14:1","text":"\u201cMan who is born of a woman is few of days and full of trouble.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":1},{"ref":"Job 14:2","short":"Job 14:2","text":"He comes out like a flower and withers; he flees like a shadow and continues not.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":2},{"ref":"Job 14:3","short":"Job 14:3","text":"And do you open your eyes on such a one and bring me into judgment with you?","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":3},{"ref":"Job 14:4","short":"Job 14:4","text":"Who can bring a clean thing out of an unclean? There is not one.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":4},{"ref":"Job 14:5","short":"Job 14:5","text":"Since his days are determined, and the number of his months is with you, and you have appointed his limits that he cannot pass,","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":5},{"ref":"Job 14:6","short":"Job 14:6","text":"look away from him and leave him alone, that he may enjoy, like a hired hand, his day.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":6},{"ref":"Job 14:7","short":"Job 14:7","text":"\u201cFor there is hope for a tree, if it be cut down, that it will sprout again, and that its shoots will not cease.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":7},{"ref":"Job 14:8","short":"Job 14:8","text":"Though its root grow old in the earth, and its stump die in the soil,","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":8},{"ref":"Job 14:9","short":"Job 14:9","text":"yet at the scent of water it will bud and put out branches like a young plant.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":9},{"ref":"Job 14:10","short":"Job 14:10","text":"But a man dies and is laid low; man breathes his last, and where is he?","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":10},{"ref":"Job 14:11","short":"Job 14:11","text":"As waters fail from a lake and a river wastes away and dries up,","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":11},{"ref":"Job 14:12","short":"Job 14:12","text":"so a man lies down and rises not again; till the heavens are no more he will not awake or be roused out of his sleep.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":12},{"ref":"Job 14:13","short":"Job 14:13","text":"Oh that you would hide me in Sheol, that you would conceal me until your wrath be past, that you would appoint me a set time, and remember me!","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":13},{"ref":"Job 14:14","short":"Job 14:14","text":"If a man dies, shall he live again? All the days of my service I would wait, till my renewal should come.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":14},{"ref":"Job 14:15","short":"Job 14:15","text":"You would call, and I would answer you; you would long for the work of your hands.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":15},{"ref":"Job 14:16","short":"Job 14:16","text":"For then you would number my steps; you would not keep watch over my sin;","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":16},{"ref":"Job 14:17","short":"Job 14:17","text":"my transgression would be sealed up in a bag, and you would cover over my iniquity.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":17},{"ref":"Job 14:18","short":"Job 14:18","text":"\u201cBut the mountain falls and crumbles away, and the rock is removed from its place;","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":18},{"ref":"Job 14:19","short":"Job 14:19","text":"the waters wear away the stones; the torrents wash away the soil of the earth; so you destroy the hope of man.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":19},{"ref":"Job 14:20","short":"Job 14:20","text":"You prevail forever against him, and he passes; you change his countenance, and send him away.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":20},{"ref":"Job 14:21","short":"Job 14:21","text":"His sons come to honor, and he does not know it; they are brought low, and he perceives it not.","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":21},{"ref":"Job 14:22","short":"Job 14:22","text":"He feels only the pain of his own body, and he mourns only for himself.\u201d","url":"ot/job/Job_14.html","book":"Job","ch":14,"v":22},{"ref":"Job 15:1","short":"Job 15:1","text":"Then Eliphaz the Temanite answered and said:","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":1},{"ref":"Job 15:2","short":"Job 15:2","text":"\u201cShould a wise man answer with windy knowledge, and fill his belly with the east wind?","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":2},{"ref":"Job 15:3","short":"Job 15:3","text":"Should he argue in unprofitable talk, or in words with which he can do no good?","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":3},{"ref":"Job 15:4","short":"Job 15:4","text":"But you are doing away with the fear of God and hindering meditation before God.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":4},{"ref":"Job 15:5","short":"Job 15:5","text":"For your iniquity teaches your mouth, and you choose the tongue of the crafty.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":5},{"ref":"Job 15:6","short":"Job 15:6","text":"Your own mouth condemns you, and not I; your own lips testify against you.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":6},{"ref":"Job 15:7","short":"Job 15:7","text":"\u201cAre you the first man who was born? Or were you brought forth before the hills?","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":7},{"ref":"Job 15:8","short":"Job 15:8","text":"Have you listened in the council of God? And do you limit wisdom to yourself?","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":8},{"ref":"Job 15:9","short":"Job 15:9","text":"What do you know that we do not know? What do you understand that is not clear to us?","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":9},{"ref":"Job 15:10","short":"Job 15:10","text":"Both the gray-haired and the aged are among us, older than your father.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":10},{"ref":"Job 15:11","short":"Job 15:11","text":"Are the comforts of God too small for you, or the word that deals gently with you?","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":11},{"ref":"Job 15:12","short":"Job 15:12","text":"Why does your heart carry you away, and why do your eyes flash,","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":12},{"ref":"Job 15:13","short":"Job 15:13","text":"that you turn your spirit against God and bring such words out of your mouth?","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":13},{"ref":"Job 15:14","short":"Job 15:14","text":"What is man, that he can be pure? Or he who is born of a woman, that he can be righteous?","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":14},{"ref":"Job 15:15","short":"Job 15:15","text":"Behold, God puts no trust in his holy ones, and the heavens are not pure in his sight;","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":15},{"ref":"Job 15:16","short":"Job 15:16","text":"how much less one who is abominable and corrupt, a man who drinks injustice like water!","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":16},{"ref":"Job 15:17","short":"Job 15:17","text":"\u201cI will show you; hear me, and what I have seen I will declare","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":17},{"ref":"Job 15:18","short":"Job 15:18","text":"(what wise men have told, without hiding it from their fathers,","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":18},{"ref":"Job 15:19","short":"Job 15:19","text":"to whom alone the land was given, and no stranger passed among them).","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":19},{"ref":"Job 15:20","short":"Job 15:20","text":"The wicked man writhes in pain all his days, through all the years that are laid up for the ruthless.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":20},{"ref":"Job 15:21","short":"Job 15:21","text":"Dreadful sounds are in his ears; in prosperity the destroyer will come upon him.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":21},{"ref":"Job 15:22","short":"Job 15:22","text":"He does not believe that he will return out of darkness, and he is marked for the sword.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":22},{"ref":"Job 15:23","short":"Job 15:23","text":"He wanders abroad for bread, saying, \u2018Where is it?\u2019 He knows that a day of darkness is ready at his hand;","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":23},{"ref":"Job 15:24","short":"Job 15:24","text":"distress and anguish terrify him; they prevail against him, like a king ready for battle.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":24},{"ref":"Job 15:25","short":"Job 15:25","text":"Because he has stretched out his hand against God and defies the Almighty,","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":25},{"ref":"Job 15:26","short":"Job 15:26","text":"running stubbornly against him with a thickly bossed shield;","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":26},{"ref":"Job 15:27","short":"Job 15:27","text":"because he has covered his face with his fat and gathered fat upon his waist","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":27},{"ref":"Job 15:28","short":"Job 15:28","text":"and has lived in desolate cities, in houses that none should inhabit, which were ready to become heaps of ruins;","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":28},{"ref":"Job 15:29","short":"Job 15:29","text":"he will not be rich, and his wealth will not endure, nor will his possessions spread over the earth;","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":29},{"ref":"Job 15:30","short":"Job 15:30","text":"he will not depart from darkness; the flame will dry up his shoots, and by the breath of his mouth he will depart.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":30},{"ref":"Job 15:31","short":"Job 15:31","text":"Let him not trust in emptiness, deceiving himself, for emptiness will be his payment.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":31},{"ref":"Job 15:32","short":"Job 15:32","text":"It will be paid in full before his time, and his branch will not be green.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":32},{"ref":"Job 15:33","short":"Job 15:33","text":"He will shake off his unripe grape like the vine, and cast off his blossom like the olive tree.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":33},{"ref":"Job 15:34","short":"Job 15:34","text":"For the company of the godless is barren, and fire consumes the tents of bribery.","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":34},{"ref":"Job 15:35","short":"Job 15:35","text":"They conceive trouble and give birth to evil, and their womb prepares deceit.\u201d","url":"ot/job/Job_15.html","book":"Job","ch":15,"v":35},{"ref":"Job 16:1","short":"Job 16:1","text":"Then Job answered and said:","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":1},{"ref":"Job 16:2","short":"Job 16:2","text":"\u201cI have heard many such things; miserable comforters are you all.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":2},{"ref":"Job 16:3","short":"Job 16:3","text":"Shall windy words have an end? Or what provokes you that you answer?","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":3},{"ref":"Job 16:4","short":"Job 16:4","text":"I also could speak as you do, if you were in my place; I could join words together against you and shake my head at you.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":4},{"ref":"Job 16:5","short":"Job 16:5","text":"I could strengthen you with my mouth, and the solace of my lips would assuage your pain.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":5},{"ref":"Job 16:6","short":"Job 16:6","text":"\u201cIf I speak, my pain is not assuaged, and if I forbear, how much of it leaves me?","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":6},{"ref":"Job 16:7","short":"Job 16:7","text":"Surely now God has worn me out; he has made desolate all my company.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":7},{"ref":"Job 16:8","short":"Job 16:8","text":"And he has shriveled me up, which is a witness against me, and my leanness has risen up against me; it testifies to my face.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":8},{"ref":"Job 16:9","short":"Job 16:9","text":"He has torn me in his wrath and hated me; he has gnashed his teeth at me; my adversary sharpens his eyes against me.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":9},{"ref":"Job 16:10","short":"Job 16:10","text":"Men have gaped at me with their mouth; they have struck me insolently on the cheek; they mass themselves together against me.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":10},{"ref":"Job 16:11","short":"Job 16:11","text":"God gives me up to the ungodly and casts me into the hands of the wicked.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":11},{"ref":"Job 16:12","short":"Job 16:12","text":"I was at ease, and he broke me apart; he seized me by the neck and dashed me to pieces; he set me up as his target;","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":12},{"ref":"Job 16:13","short":"Job 16:13","text":"his archers surround me. He slashes open my kidneys and does not spare; he pours out my gall on the ground.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":13},{"ref":"Job 16:14","short":"Job 16:14","text":"He breaks me with breach upon breach; he runs upon me like a warrior.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":14},{"ref":"Job 16:15","short":"Job 16:15","text":"I have sewed sackcloth upon my skin and have laid my strength in the dust.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":15},{"ref":"Job 16:16","short":"Job 16:16","text":"My face is red with weeping, and on my eyelids is deep darkness,","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":16},{"ref":"Job 16:17","short":"Job 16:17","text":"although there is no violence in my hands, and my prayer is pure.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":17},{"ref":"Job 16:18","short":"Job 16:18","text":"\u201cO earth, cover not my blood, and let my cry find no resting place.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":18},{"ref":"Job 16:19","short":"Job 16:19","text":"Even now, behold, my witness is in heaven, and he who testifies for me is on high.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":19},{"ref":"Job 16:20","short":"Job 16:20","text":"My friends scorn me; my eye pours out tears to God,","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":20},{"ref":"Job 16:21","short":"Job 16:21","text":"that he would argue the case of a man with God, as a son of man does with his neighbor.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":21},{"ref":"Job 16:22","short":"Job 16:22","text":"For when a few years have come I shall go the way from which I shall not return.","url":"ot/job/Job_16.html","book":"Job","ch":16,"v":22},{"ref":"Job 17:1","short":"Job 17:1","text":"\u201cMy spirit is broken; my days are extinct; the graveyard is ready for me.","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":1},{"ref":"Job 17:2","short":"Job 17:2","text":"Surely there are mockers about me, and my eye dwells on their provocation.","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":2},{"ref":"Job 17:3","short":"Job 17:3","text":"\u201cLay down a pledge for me with you; who is there who will put up security for me?","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":3},{"ref":"Job 17:4","short":"Job 17:4","text":"Since you have closed their hearts to understanding, therefore you will not let them triumph.","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":4},{"ref":"Job 17:5","short":"Job 17:5","text":"He who informs against his friends to get a share of their property\u2014 the eyes of his children will fail.","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":5},{"ref":"Job 17:6","short":"Job 17:6","text":"\u201cHe has made me a byword of the peoples, and I am one before whom men spit.","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":6},{"ref":"Job 17:7","short":"Job 17:7","text":"My eye has grown dim from vexation, and all my members are like a shadow.","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":7},{"ref":"Job 17:8","short":"Job 17:8","text":"The upright are appalled at this, and the innocent stirs himself up against the godless.","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":8},{"ref":"Job 17:9","short":"Job 17:9","text":"Yet the righteous holds to his way, and he who has clean hands grows stronger and stronger.","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":9},{"ref":"Job 17:10","short":"Job 17:10","text":"But you, come on again, all of you, and I shall not find a wise man among you.","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":10},{"ref":"Job 17:11","short":"Job 17:11","text":"My days are past; my plans are broken off, the desires of my heart.","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":11},{"ref":"Job 17:12","short":"Job 17:12","text":"They make night into day: \u2018The light,\u2019 they say, \u2018is near to the darkness.\u2019","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":12},{"ref":"Job 17:13","short":"Job 17:13","text":"If I hope for Sheol as my house, if I make my bed in darkness,","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":13},{"ref":"Job 17:14","short":"Job 17:14","text":"if I say to the pit, \u2018You are my father,\u2019 and to the worm, \u2018My mother,\u2019 or \u2018My sister,\u2019","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":14},{"ref":"Job 17:15","short":"Job 17:15","text":"where then is my hope? Who will see my hope?","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":15},{"ref":"Job 17:16","short":"Job 17:16","text":"Will it go down to the bars of Sheol? Shall we descend together into the dust?\u201d","url":"ot/job/Job_17.html","book":"Job","ch":17,"v":16},{"ref":"Job 18:1","short":"Job 18:1","text":"Then Bildad the Shuhite answered and said:","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":1},{"ref":"Job 18:2","short":"Job 18:2","text":"\u201cHow long will you hunt for words? Consider, and then we will speak.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":2},{"ref":"Job 18:3","short":"Job 18:3","text":"Why are we counted as cattle? Why are we stupid in your sight?","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":3},{"ref":"Job 18:4","short":"Job 18:4","text":"You who tear yourself in your anger, shall the earth be forsaken for you, or the rock be removed out of its place?","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":4},{"ref":"Job 18:5","short":"Job 18:5","text":"\u201cIndeed, the light of the wicked is put out, and the flame of his fire does not shine.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":5},{"ref":"Job 18:6","short":"Job 18:6","text":"The light is dark in his tent, and his lamp above him is put out.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":6},{"ref":"Job 18:7","short":"Job 18:7","text":"His strong steps are shortened, and his own schemes throw him down.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":7},{"ref":"Job 18:8","short":"Job 18:8","text":"For he is cast into a net by his own feet, and he walks on its mesh.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":8},{"ref":"Job 18:9","short":"Job 18:9","text":"A trap seizes him by the heel; a snare lays hold of him.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":9},{"ref":"Job 18:10","short":"Job 18:10","text":"A rope is hidden for him in the ground, a trap for him in the path.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":10},{"ref":"Job 18:11","short":"Job 18:11","text":"Terrors frighten him on every side, and chase him at his heels.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":11},{"ref":"Job 18:12","short":"Job 18:12","text":"His strength is famished, and calamity is ready for his stumbling.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":12},{"ref":"Job 18:13","short":"Job 18:13","text":"It consumes the parts of his skin; the firstborn of death consumes his limbs.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":13},{"ref":"Job 18:14","short":"Job 18:14","text":"He is torn from the tent in which he trusted and is brought to the king of terrors.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":14},{"ref":"Job 18:15","short":"Job 18:15","text":"In his tent dwells that which is none of his; sulfur is scattered over his habitation.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":15},{"ref":"Job 18:16","short":"Job 18:16","text":"His roots dry up beneath, and his branches wither above.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":16},{"ref":"Job 18:17","short":"Job 18:17","text":"His memory perishes from the earth, and he has no name in the street.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":17},{"ref":"Job 18:18","short":"Job 18:18","text":"He is thrust from light into darkness, and driven out of the world.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":18},{"ref":"Job 18:19","short":"Job 18:19","text":"He has no posterity or progeny among his people, and no survivor where he used to live.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":19},{"ref":"Job 18:20","short":"Job 18:20","text":"They of the west are appalled at his day, and horror seizes them of the east.","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":20},{"ref":"Job 18:21","short":"Job 18:21","text":"Surely such are the dwellings of the unrighteous, such is the place of him who knows not God.\u201d","url":"ot/job/Job_18.html","book":"Job","ch":18,"v":21},{"ref":"Job 19:1","short":"Job 19:1","text":"Then Job answered and said:","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":1},{"ref":"Job 19:2","short":"Job 19:2","text":"\u201cHow long will you torment me and break me in pieces with words?","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":2},{"ref":"Job 19:3","short":"Job 19:3","text":"These ten times you have cast reproach upon me; are you not ashamed to wrong me?","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":3},{"ref":"Job 19:4","short":"Job 19:4","text":"And even if it be true that I have erred, my error remains with myself.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":4},{"ref":"Job 19:5","short":"Job 19:5","text":"If indeed you magnify yourselves against me and make my disgrace an argument against me,","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":5},{"ref":"Job 19:6","short":"Job 19:6","text":"know then that God has put me in the wrong and closed his net about me.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":6},{"ref":"Job 19:7","short":"Job 19:7","text":"Behold, I cry out, \u2018Violence!\u2019 but I am not answered; I call for help, but there is no justice.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":7},{"ref":"Job 19:8","short":"Job 19:8","text":"He has walled up my way, so that I cannot pass, and he has set darkness upon my paths.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":8},{"ref":"Job 19:9","short":"Job 19:9","text":"He has stripped from me my glory and taken the crown from my head.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":9},{"ref":"Job 19:10","short":"Job 19:10","text":"He breaks me down on every side, and I am gone, and my hope has he pulled up like a tree.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":10},{"ref":"Job 19:11","short":"Job 19:11","text":"He has kindled his wrath against me and counts me as his adversary.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":11},{"ref":"Job 19:12","short":"Job 19:12","text":"His troops come on together; they have cast up their siege ramp against me and encamp around my tent.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":12},{"ref":"Job 19:13","short":"Job 19:13","text":"\u201cHe has put my brothers far from me, and those who knew me are wholly estranged from me.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":13},{"ref":"Job 19:14","short":"Job 19:14","text":"My relatives have failed me, my close friends have forgotten me.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":14},{"ref":"Job 19:15","short":"Job 19:15","text":"The guests in my house and my maidservants count me as a stranger; I have become a foreigner in their eyes.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":15},{"ref":"Job 19:16","short":"Job 19:16","text":"I call to my servant, but he gives me no answer; I must plead with him with my mouth for mercy.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":16},{"ref":"Job 19:17","short":"Job 19:17","text":"My breath is strange to my wife, and I am a stench to the children of my own mother.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":17},{"ref":"Job 19:18","short":"Job 19:18","text":"Even young children despise me; when I rise they talk against me.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":18},{"ref":"Job 19:19","short":"Job 19:19","text":"All my intimate friends abhor me, and those whom I loved have turned against me.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":19},{"ref":"Job 19:20","short":"Job 19:20","text":"My bones stick to my skin and to my flesh, and I have escaped by the skin of my teeth.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":20},{"ref":"Job 19:21","short":"Job 19:21","text":"Have mercy on me, have mercy on me, O you my friends, for the hand of God has touched me!","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":21},{"ref":"Job 19:22","short":"Job 19:22","text":"Why do you, like God, pursue me? Why are you not satisfied with my flesh?","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":22},{"ref":"Job 19:23","short":"Job 19:23","text":"\u201cOh that my words were written! Oh that they were inscribed in a book!","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":23},{"ref":"Job 19:24","short":"Job 19:24","text":"Oh that with an iron pen and lead they were engraved in the rock forever!","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":24},{"ref":"Job 19:25","short":"Job 19:25","text":"For I know that my Redeemer lives, and at the last he will stand upon the earth.","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":25},{"ref":"Job 19:26","short":"Job 19:26","text":"And after my skin has been thus destroyed, yet in my flesh I shall see God,","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":26},{"ref":"Job 19:27","short":"Job 19:27","text":"whom I shall see for myself, and my eyes shall behold, and not another. My heart faints within me!","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":27},{"ref":"Job 19:28","short":"Job 19:28","text":"If you say, \u2018How we will pursue him!\u2019 and, \u2018The root of the matter is found in him,\u2019","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":28},{"ref":"Job 19:29","short":"Job 19:29","text":"be afraid of the sword, for wrath brings the punishment of the sword, that you may know there is a judgment.\u201d","url":"ot/job/Job_19.html","book":"Job","ch":19,"v":29},{"ref":"Job 20:1","short":"Job 20:1","text":"Then Zophar the Naamathite answered and said:","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":1},{"ref":"Job 20:2","short":"Job 20:2","text":"\u201cTherefore my thoughts answer me, because of my haste within me.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":2},{"ref":"Job 20:3","short":"Job 20:3","text":"I hear censure that insults me, and out of my understanding a spirit answers me.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":3},{"ref":"Job 20:4","short":"Job 20:4","text":"Do you not know this from of old, since man was placed on earth,","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":4},{"ref":"Job 20:5","short":"Job 20:5","text":"that the exulting of the wicked is short, and the joy of the godless but for a moment?","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":5},{"ref":"Job 20:6","short":"Job 20:6","text":"Though his height mount up to the heavens, and his head reach to the clouds,","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":6},{"ref":"Job 20:7","short":"Job 20:7","text":"he will perish forever like his own dung; those who have seen him will say, \u2018Where is he?\u2019","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":7},{"ref":"Job 20:8","short":"Job 20:8","text":"He will fly away like a dream and not be found; he will be chased away like a vision of the night.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":8},{"ref":"Job 20:9","short":"Job 20:9","text":"The eye that saw him will see him no more, nor will his place any more behold him.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":9},{"ref":"Job 20:10","short":"Job 20:10","text":"His children will seek the favor of the poor, and his hands will give back his wealth.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":10},{"ref":"Job 20:11","short":"Job 20:11","text":"His bones are full of his youthful vigor, but it will lie down with him in the dust.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":11},{"ref":"Job 20:12","short":"Job 20:12","text":"\u201cThough evil is sweet in his mouth, though he hides it under his tongue,","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":12},{"ref":"Job 20:13","short":"Job 20:13","text":"though he is loath to let it go and holds it in his mouth,","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":13},{"ref":"Job 20:14","short":"Job 20:14","text":"yet his food is turned in his stomach; it is the venom of cobras within him.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":14},{"ref":"Job 20:15","short":"Job 20:15","text":"He swallows down riches and vomits them up again; God casts them out of his belly.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":15},{"ref":"Job 20:16","short":"Job 20:16","text":"He will suck the poison of cobras; the tongue of a viper will kill him.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":16},{"ref":"Job 20:17","short":"Job 20:17","text":"He will not look upon the rivers, the streams flowing with honey and curds.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":17},{"ref":"Job 20:18","short":"Job 20:18","text":"He will give back the fruit of his toil and will not swallow it down; from the profit of his trading he will get no enjoyment.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":18},{"ref":"Job 20:19","short":"Job 20:19","text":"For he has crushed and abandoned the poor; he has seized a house that he did not build.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":19},{"ref":"Job 20:20","short":"Job 20:20","text":"\u201cBecause he knew no contentment in his belly, he will not let anything in which he delights escape him.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":20},{"ref":"Job 20:21","short":"Job 20:21","text":"There was nothing left after he had eaten; therefore his prosperity will not endure.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":21},{"ref":"Job 20:22","short":"Job 20:22","text":"In the fullness of his sufficiency he will be in distress; the hand of everyone in misery will come against him.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":22},{"ref":"Job 20:23","short":"Job 20:23","text":"To fill his belly to the full, God will send his burning anger against him and rain it upon him into his body.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":23},{"ref":"Job 20:24","short":"Job 20:24","text":"He will flee from an iron weapon; a bronze arrow will strike him through.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":24},{"ref":"Job 20:25","short":"Job 20:25","text":"It is drawn forth and comes out of his body; the glittering point comes out of his gallbladder; terrors come upon him.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":25},{"ref":"Job 20:26","short":"Job 20:26","text":"Utter darkness is laid up for his treasures; a fire not fanned will devour him; what is left in his tent will be consumed.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":26},{"ref":"Job 20:27","short":"Job 20:27","text":"The heavens will reveal his iniquity, and the earth will rise up against him.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":27},{"ref":"Job 20:28","short":"Job 20:28","text":"The possessions of his house will be carried away, dragged off in the day of God\u2019s wrath.","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":28},{"ref":"Job 20:29","short":"Job 20:29","text":"This is the wicked man\u2019s portion from God, the heritage decreed for him by God.\u201d","url":"ot/job/Job_20.html","book":"Job","ch":20,"v":29},{"ref":"Job 21:1","short":"Job 21:1","text":"Then Job answered and said:","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":1},{"ref":"Job 21:2","short":"Job 21:2","text":"\u201cKeep listening to my words, and let this be your comfort.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":2},{"ref":"Job 21:3","short":"Job 21:3","text":"Bear with me, and I will speak, and after I have spoken, mock on.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":3},{"ref":"Job 21:4","short":"Job 21:4","text":"As for me, is my complaint against man? Why should I not be impatient?","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":4},{"ref":"Job 21:5","short":"Job 21:5","text":"Look at me and be appalled, and lay your hand over your mouth.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":5},{"ref":"Job 21:6","short":"Job 21:6","text":"When I remember, I am dismayed, and shuddering seizes my flesh.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":6},{"ref":"Job 21:7","short":"Job 21:7","text":"Why do the wicked live, reach old age, and grow mighty in power?","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":7},{"ref":"Job 21:8","short":"Job 21:8","text":"Their offspring are established in their presence, and their descendants before their eyes.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":8},{"ref":"Job 21:9","short":"Job 21:9","text":"Their houses are safe from fear, and no rod of God is upon them.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":9},{"ref":"Job 21:10","short":"Job 21:10","text":"Their bull breeds without fail; their cow calves and does not miscarry.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":10},{"ref":"Job 21:11","short":"Job 21:11","text":"They send out their little boys like a flock, and their children dance.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":11},{"ref":"Job 21:12","short":"Job 21:12","text":"They sing to the tambourine and the lyre and rejoice to the sound of the pipe.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":12},{"ref":"Job 21:13","short":"Job 21:13","text":"They spend their days in prosperity, and in peace they go down to Sheol.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":13},{"ref":"Job 21:14","short":"Job 21:14","text":"They say to God, \u2018Depart from us! We do not desire the knowledge of your ways.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":14},{"ref":"Job 21:15","short":"Job 21:15","text":"What is the Almighty, that we should serve him? And what profit do we get if we pray to him?\u2019","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":15},{"ref":"Job 21:16","short":"Job 21:16","text":"Behold, is not their prosperity in their hand? The counsel of the wicked is far from me.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":16},{"ref":"Job 21:17","short":"Job 21:17","text":"\u201cHow often is it that the lamp of the wicked is put out? That their calamity comes upon them? That God distributes pains in his anger?","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":17},{"ref":"Job 21:18","short":"Job 21:18","text":"That they are like straw before the wind, and like chaff that the storm carries away?","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":18},{"ref":"Job 21:19","short":"Job 21:19","text":"You say, \u2018God stores up their iniquity for their children.\u2019 Let him pay it out to them, that they may know it.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":19},{"ref":"Job 21:20","short":"Job 21:20","text":"Let their own eyes see their destruction, and let them drink of the wrath of the Almighty.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":20},{"ref":"Job 21:21","short":"Job 21:21","text":"For what do they care for their houses after them, when the number of their months is cut off?","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":21},{"ref":"Job 21:22","short":"Job 21:22","text":"Will any teach God knowledge, seeing that he judges those who are on high?","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":22},{"ref":"Job 21:23","short":"Job 21:23","text":"One dies in his full vigor, being wholly at ease and secure,","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":23},{"ref":"Job 21:24","short":"Job 21:24","text":"his pails full of milk and the marrow of his bones moist.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":24},{"ref":"Job 21:25","short":"Job 21:25","text":"Another dies in bitterness of soul, never having tasted of prosperity.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":25},{"ref":"Job 21:26","short":"Job 21:26","text":"They lie down alike in the dust, and the worms cover them.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":26},{"ref":"Job 21:27","short":"Job 21:27","text":"\u201cBehold, I know your thoughts and your schemes to wrong me.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":27},{"ref":"Job 21:28","short":"Job 21:28","text":"For you say, \u2018Where is the house of the prince? Where is the tent in which the wicked lived?\u2019","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":28},{"ref":"Job 21:29","short":"Job 21:29","text":"Have you not asked those who travel the roads, and do you not accept their testimony","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":29},{"ref":"Job 21:30","short":"Job 21:30","text":"that the evil man is spared in the day of calamity, that he is rescued in the day of wrath?","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":30},{"ref":"Job 21:31","short":"Job 21:31","text":"Who declares his way to his face, and who repays him for what he has done?","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":31},{"ref":"Job 21:32","short":"Job 21:32","text":"When he is carried to the grave, watch is kept over his tomb.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":32},{"ref":"Job 21:33","short":"Job 21:33","text":"The clods of the valley are sweet to him; all mankind follows after him, and those who go before him are innumerable.","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":33},{"ref":"Job 21:34","short":"Job 21:34","text":"How then will you comfort me with empty nothings? There is nothing left of your answers but falsehood.\u201d","url":"ot/job/Job_21.html","book":"Job","ch":21,"v":34},{"ref":"Job 22:1","short":"Job 22:1","text":"Then Eliphaz the Temanite answered and said:","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":1},{"ref":"Job 22:2","short":"Job 22:2","text":"\u201cCan a man be profitable to God? Surely he who is wise is profitable to himself.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":2},{"ref":"Job 22:3","short":"Job 22:3","text":"Is it any pleasure to the Almighty if you are in the right, or is it gain to him if you make your ways blameless?","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":3},{"ref":"Job 22:4","short":"Job 22:4","text":"Is it for your fear of him that he reproves you and enters into judgment with you?","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":4},{"ref":"Job 22:5","short":"Job 22:5","text":"Is not your evil abundant? There is no end to your iniquities.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":5},{"ref":"Job 22:6","short":"Job 22:6","text":"For you have exacted pledges of your brothers for nothing and stripped the naked of their clothing.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":6},{"ref":"Job 22:7","short":"Job 22:7","text":"You have given no water to the weary to drink, and you have withheld bread from the hungry.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":7},{"ref":"Job 22:8","short":"Job 22:8","text":"The man with power possessed the land, and the favored man lived in it.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":8},{"ref":"Job 22:9","short":"Job 22:9","text":"You have sent widows away empty, and the arms of the fatherless were crushed.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":9},{"ref":"Job 22:10","short":"Job 22:10","text":"Therefore snares are all around you, and sudden terror overwhelms you,","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":10},{"ref":"Job 22:11","short":"Job 22:11","text":"or darkness, so that you cannot see, and a flood of water covers you.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":11},{"ref":"Job 22:12","short":"Job 22:12","text":"\u201cIs not God high in the heavens? See the highest stars, how lofty they are!","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":12},{"ref":"Job 22:13","short":"Job 22:13","text":"But you say, \u2018What does God know? Can he judge through the deep darkness?","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":13},{"ref":"Job 22:14","short":"Job 22:14","text":"Thick clouds veil him, so that he does not see, and he walks on the vault of heaven.\u2019","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":14},{"ref":"Job 22:15","short":"Job 22:15","text":"Will you keep to the old way that wicked men have trod?","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":15},{"ref":"Job 22:16","short":"Job 22:16","text":"They were snatched away before their time; their foundation was washed away.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":16},{"ref":"Job 22:17","short":"Job 22:17","text":"They said to God, \u2018Depart from us,\u2019 and \u2018What can the Almighty do to us?\u2019","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":17},{"ref":"Job 22:18","short":"Job 22:18","text":"Yet he filled their houses with good things\u2014 but the counsel of the wicked is far from me.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":18},{"ref":"Job 22:19","short":"Job 22:19","text":"The righteous see it and are glad; the innocent one mocks at them,","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":19},{"ref":"Job 22:20","short":"Job 22:20","text":"saying, \u2018Surely our adversaries are cut off, and what they left the fire has consumed.\u2019","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":20},{"ref":"Job 22:21","short":"Job 22:21","text":"\u201cAgree with God, and be at peace; thereby good will come to you.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":21},{"ref":"Job 22:22","short":"Job 22:22","text":"Receive instruction from his mouth, and lay up his words in your heart.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":22},{"ref":"Job 22:23","short":"Job 22:23","text":"If you return to the Almighty you will be built up; if you remove injustice far from your tents,","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":23},{"ref":"Job 22:24","short":"Job 22:24","text":"if you lay gold in the dust, and gold of Ophir among the stones of the torrent-bed,","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":24},{"ref":"Job 22:25","short":"Job 22:25","text":"then the Almighty will be your gold and your precious silver.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":25},{"ref":"Job 22:26","short":"Job 22:26","text":"For then you will delight yourself in the Almighty and lift up your face to God.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":26},{"ref":"Job 22:27","short":"Job 22:27","text":"You will make your prayer to him, and he will hear you, and you will pay your vows.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":27},{"ref":"Job 22:28","short":"Job 22:28","text":"You will decide on a matter, and it will be established for you, and light will shine on your ways.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":28},{"ref":"Job 22:29","short":"Job 22:29","text":"For when they are humbled you say, \u2018It is because of pride\u2019; but he saves the lowly.","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":29},{"ref":"Job 22:30","short":"Job 22:30","text":"He delivers even the one who is not innocent, who will be delivered through the cleanness of your hands.\u201d","url":"ot/job/Job_22.html","book":"Job","ch":22,"v":30},{"ref":"Job 23:1","short":"Job 23:1","text":"Then Job answered and said:","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":1},{"ref":"Job 23:2","short":"Job 23:2","text":"\u201cToday also my complaint is bitter; my hand is heavy on account of my groaning.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":2},{"ref":"Job 23:3","short":"Job 23:3","text":"Oh, that I knew where I might find him, that I might come even to his seat!","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":3},{"ref":"Job 23:4","short":"Job 23:4","text":"I would lay my case before him and fill my mouth with arguments.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":4},{"ref":"Job 23:5","short":"Job 23:5","text":"I would know what he would answer me and understand what he would say to me.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":5},{"ref":"Job 23:6","short":"Job 23:6","text":"Would he contend with me in the greatness of his power? No; he would pay attention to me.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":6},{"ref":"Job 23:7","short":"Job 23:7","text":"There an upright man could argue with him, and I would be acquitted forever by my judge.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":7},{"ref":"Job 23:8","short":"Job 23:8","text":"\u201cBehold, I go forward, but he is not there, and backward, but I do not perceive him;","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":8},{"ref":"Job 23:9","short":"Job 23:9","text":"on the left hand when he is working, I do not behold him; he turns to the right hand, but I do not see him.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":9},{"ref":"Job 23:10","short":"Job 23:10","text":"But he knows the way that I take; when he has tried me, I shall come out as gold.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":10},{"ref":"Job 23:11","short":"Job 23:11","text":"My foot has held fast to his steps; I have kept his way and have not turned aside.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":11},{"ref":"Job 23:12","short":"Job 23:12","text":"I have not departed from the commandment of his lips; I have treasured the words of his mouth more than my portion of food.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":12},{"ref":"Job 23:13","short":"Job 23:13","text":"But he is unchangeable, and who can turn him back? What he desires, that he does.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":13},{"ref":"Job 23:14","short":"Job 23:14","text":"For he will complete what he appoints for me, and many such things are in his mind.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":14},{"ref":"Job 23:15","short":"Job 23:15","text":"Therefore I am terrified at his presence; when I consider, I am in dread of him.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":15},{"ref":"Job 23:16","short":"Job 23:16","text":"God has made my heart faint; the Almighty has terrified me;","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":16},{"ref":"Job 23:17","short":"Job 23:17","text":"yet I am not silenced because of the darkness, nor because thick darkness covers my face.","url":"ot/job/Job_23.html","book":"Job","ch":23,"v":17},{"ref":"Job 24:1","short":"Job 24:1","text":"\u201cWhy are not times of judgment kept by the Almighty, and why do those who know him never see his days?","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":1},{"ref":"Job 24:2","short":"Job 24:2","text":"Some move landmarks; they seize flocks and pasture them.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":2},{"ref":"Job 24:3","short":"Job 24:3","text":"They drive away the donkey of the fatherless; they take the widow\u2019s ox for a pledge.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":3},{"ref":"Job 24:4","short":"Job 24:4","text":"They thrust the poor off the road; the poor of the earth all hide themselves.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":4},{"ref":"Job 24:5","short":"Job 24:5","text":"Behold, like wild donkeys in the desert the poor go out to their toil, seeking game; the wasteland yields food for their children.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":5},{"ref":"Job 24:6","short":"Job 24:6","text":"They gather their fodder in the field, and they glean the vineyard of the wicked man.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":6},{"ref":"Job 24:7","short":"Job 24:7","text":"They lie all night naked, without clothing, and have no covering in the cold.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":7},{"ref":"Job 24:8","short":"Job 24:8","text":"They are wet with the rain of the mountains and cling to the rock for lack of shelter.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":8},{"ref":"Job 24:9","short":"Job 24:9","text":"(There are those who snatch the fatherless child from the breast, and they take a pledge against the poor.)","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":9},{"ref":"Job 24:10","short":"Job 24:10","text":"They go about naked, without clothing; hungry, they carry the sheaves;","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":10},{"ref":"Job 24:11","short":"Job 24:11","text":"among the olive rows of the wicked they make oil; they tread the winepresses, but suffer thirst.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":11},{"ref":"Job 24:12","short":"Job 24:12","text":"From out of the city the dying groan, and the soul of the wounded cries for help; yet God charges no one with wrong.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":12},{"ref":"Job 24:13","short":"Job 24:13","text":"\u201cThere are those who rebel against the light, who are not acquainted with its ways, and do not stay in its paths.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":13},{"ref":"Job 24:14","short":"Job 24:14","text":"The murderer rises before it is light, that he may kill the poor and needy, and in the night he is like a thief.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":14},{"ref":"Job 24:15","short":"Job 24:15","text":"The eye of the adulterer also waits for the twilight, saying, \u2018No eye will see me\u2019; and he veils his face.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":15},{"ref":"Job 24:16","short":"Job 24:16","text":"In the dark they dig through houses; by day they shut themselves up; they do not know the light.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":16},{"ref":"Job 24:17","short":"Job 24:17","text":"For deep darkness is morning to all of them; for they are friends with the terrors of deep darkness.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":17},{"ref":"Job 24:18","short":"Job 24:18","text":"\u201cYou say, \u2018Swift are they on the face of the waters; their portion is cursed in the land; no treader turns toward their vineyards.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":18},{"ref":"Job 24:19","short":"Job 24:19","text":"Drought and heat snatch away the snow waters; so does Sheol those who have sinned.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":19},{"ref":"Job 24:20","short":"Job 24:20","text":"The womb forgets them; the worm finds them sweet; they are no longer remembered, so wickedness is broken like a tree.\u2019","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":20},{"ref":"Job 24:21","short":"Job 24:21","text":"\u201cThey wrong the barren, childless woman, and do no good to the widow.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":21},{"ref":"Job 24:22","short":"Job 24:22","text":"Yet God prolongs the life of the mighty by his power; they rise up when they despair of life.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":22},{"ref":"Job 24:23","short":"Job 24:23","text":"He gives them security, and they are supported, and his eyes are upon their ways.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":23},{"ref":"Job 24:24","short":"Job 24:24","text":"They are exalted a little while, and then are gone; they are brought low and gathered up like all others; they are cut off like the heads of grain.","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":24},{"ref":"Job 24:25","short":"Job 24:25","text":"If it is not so, who will prove me a liar and show that there is nothing in what I say?\u201d","url":"ot/job/Job_24.html","book":"Job","ch":24,"v":25},{"ref":"Job 25:1","short":"Job 25:1","text":"Then Bildad the Shuhite answered and said:","url":"ot/job/Job_25.html","book":"Job","ch":25,"v":1},{"ref":"Job 25:2","short":"Job 25:2","text":"\u201cDominion and fear are with God; he makes peace in his high heaven.","url":"ot/job/Job_25.html","book":"Job","ch":25,"v":2},{"ref":"Job 25:3","short":"Job 25:3","text":"Is there any number to his armies? Upon whom does his light not arise?","url":"ot/job/Job_25.html","book":"Job","ch":25,"v":3},{"ref":"Job 25:4","short":"Job 25:4","text":"How then can man be in the right before God? How can he who is born of woman be pure?","url":"ot/job/Job_25.html","book":"Job","ch":25,"v":4},{"ref":"Job 25:5","short":"Job 25:5","text":"Behold, even the moon is not bright, and the stars are not pure in his eyes;","url":"ot/job/Job_25.html","book":"Job","ch":25,"v":5},{"ref":"Job 25:6","short":"Job 25:6","text":"how much less man, who is a maggot, and the son of man, who is a worm!\u201d","url":"ot/job/Job_25.html","book":"Job","ch":25,"v":6},{"ref":"Job 26:1","short":"Job 26:1","text":"Then Job answered and said:","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":1},{"ref":"Job 26:2","short":"Job 26:2","text":"\u201cHow you have helped him who has no power! How you have saved the arm that has no strength!","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":2},{"ref":"Job 26:3","short":"Job 26:3","text":"How you have counseled him who has no wisdom, and plentifully declared sound knowledge!","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":3},{"ref":"Job 26:4","short":"Job 26:4","text":"With whose help have you uttered words, and whose breath has come out from you?","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":4},{"ref":"Job 26:5","short":"Job 26:5","text":"The dead tremble under the waters and their inhabitants.","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":5},{"ref":"Job 26:6","short":"Job 26:6","text":"Sheol is naked before God, and Abaddon has no covering.","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":6},{"ref":"Job 26:7","short":"Job 26:7","text":"He stretches out the north over the void and hangs the earth on nothing.","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":7},{"ref":"Job 26:8","short":"Job 26:8","text":"He binds up the waters in his thick clouds, and the cloud is not split open under them.","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":8},{"ref":"Job 26:9","short":"Job 26:9","text":"He covers the face of the full moon and spreads over it his cloud.","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":9},{"ref":"Job 26:10","short":"Job 26:10","text":"He has inscribed a circle on the face of the waters at the boundary between light and darkness.","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":10},{"ref":"Job 26:11","short":"Job 26:11","text":"The pillars of heaven tremble and are astounded at his rebuke.","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":11},{"ref":"Job 26:12","short":"Job 26:12","text":"By his power he stilled the sea; by his understanding he shattered Rahab.","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":12},{"ref":"Job 26:13","short":"Job 26:13","text":"By his wind the heavens were made fair; his hand pierced the fleeing serpent.","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":13},{"ref":"Job 26:14","short":"Job 26:14","text":"Behold, these are but the outskirts of his ways, and how small a whisper do we hear of him! But the thunder of his power who can understand?\u201d","url":"ot/job/Job_26.html","book":"Job","ch":26,"v":14},{"ref":"Job 27:1","short":"Job 27:1","text":"And Job again took up his discourse, and said:","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":1},{"ref":"Job 27:2","short":"Job 27:2","text":"\u201cAs God lives, who has taken away my right, and the Almighty, who has made my soul bitter,","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":2},{"ref":"Job 27:3","short":"Job 27:3","text":"as long as my breath is in me, and the spirit of God is in my nostrils,","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":3},{"ref":"Job 27:4","short":"Job 27:4","text":"my lips will not speak falsehood, and my tongue will not utter deceit.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":4},{"ref":"Job 27:5","short":"Job 27:5","text":"Far be it from me to say that you are right; till I die I will not put away my integrity from me.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":5},{"ref":"Job 27:6","short":"Job 27:6","text":"I hold fast my righteousness and will not let it go; my heart does not reproach me for any of my days.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":6},{"ref":"Job 27:7","short":"Job 27:7","text":"\u201cLet my enemy be as the wicked, and let him who rises up against me be as the unrighteous.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":7},{"ref":"Job 27:8","short":"Job 27:8","text":"For what is the hope of the godless when God cuts him off, when God takes away his life?","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":8},{"ref":"Job 27:9","short":"Job 27:9","text":"Will God hear his cry when distress comes upon him?","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":9},{"ref":"Job 27:10","short":"Job 27:10","text":"Will he take delight in the Almighty? Will he call upon God at all times?","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":10},{"ref":"Job 27:11","short":"Job 27:11","text":"I will teach you concerning the hand of God; what is with the Almighty I will not conceal.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":11},{"ref":"Job 27:12","short":"Job 27:12","text":"Behold, all of you have seen it yourselves; why then have you become altogether vain?","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":12},{"ref":"Job 27:13","short":"Job 27:13","text":"\u201cThis is the portion of a wicked man with God, and the heritage that oppressors receive from the Almighty:","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":13},{"ref":"Job 27:14","short":"Job 27:14","text":"If his children are multiplied, it is for the sword, and his descendants have not enough bread.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":14},{"ref":"Job 27:15","short":"Job 27:15","text":"Those who survive him the pestilence buries, and his widows do not weep.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":15},{"ref":"Job 27:16","short":"Job 27:16","text":"Though he heap up silver like dust, and pile up clothing like clay,","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":16},{"ref":"Job 27:17","short":"Job 27:17","text":"he may pile it up, but the righteous will wear it, and the innocent will divide the silver.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":17},{"ref":"Job 27:18","short":"Job 27:18","text":"He builds his house like a moth\u2019s, like a booth that a watchman makes.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":18},{"ref":"Job 27:19","short":"Job 27:19","text":"He goes to bed rich, but will do so no more; he opens his eyes, and his wealth is gone.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":19},{"ref":"Job 27:20","short":"Job 27:20","text":"Terrors overtake him like a flood; in the night a whirlwind carries him off.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":20},{"ref":"Job 27:21","short":"Job 27:21","text":"The east wind lifts him up and he is gone; it sweeps him out of his place.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":21},{"ref":"Job 27:22","short":"Job 27:22","text":"It hurls at him without pity; he flees from its power in headlong flight.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":22},{"ref":"Job 27:23","short":"Job 27:23","text":"It claps its hands at him and hisses at him from its place.","url":"ot/job/Job_27.html","book":"Job","ch":27,"v":23},{"ref":"Job 28:1","short":"Job 28:1","text":"\u201cSurely there is a mine for silver, and a place for gold that they refine.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":1},{"ref":"Job 28:2","short":"Job 28:2","text":"Iron is taken out of the earth, and copper is smelted from the ore.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":2},{"ref":"Job 28:3","short":"Job 28:3","text":"Man puts an end to darkness and searches out to the farthest limit the ore in gloom and deep darkness.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":3},{"ref":"Job 28:4","short":"Job 28:4","text":"He opens shafts in a valley away from where anyone lives; they are forgotten by travelers; they hang in the air, far away from mankind; they swing to and fro.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":4},{"ref":"Job 28:5","short":"Job 28:5","text":"As for the earth, out of it comes bread, but underneath it is turned up as by fire.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":5},{"ref":"Job 28:6","short":"Job 28:6","text":"Its stones are the place of sapphires, and it has dust of gold.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":6},{"ref":"Job 28:7","short":"Job 28:7","text":"\u201cThat path no bird of prey knows, and the falcon\u2019s eye has not seen it.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":7},{"ref":"Job 28:8","short":"Job 28:8","text":"The proud beasts have not trodden it; the lion has not passed over it.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":8},{"ref":"Job 28:9","short":"Job 28:9","text":"\u201cMan puts his hand to the flinty rock and overturns mountains by the roots.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":9},{"ref":"Job 28:10","short":"Job 28:10","text":"He cuts out channels in the rocks, and his eye sees every precious thing.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":10},{"ref":"Job 28:11","short":"Job 28:11","text":"He dams up the streams so that they do not trickle, and the thing that is hidden he brings out to light.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":11},{"ref":"Job 28:12","short":"Job 28:12","text":"\u201cBut where shall wisdom be found? And where is the place of understanding?","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":12},{"ref":"Job 28:13","short":"Job 28:13","text":"Man does not know its worth, and it is not found in the land of the living.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":13},{"ref":"Job 28:14","short":"Job 28:14","text":"The deep says, \u2018It is not in me,\u2019 and the sea says, \u2018It is not with me.\u2019","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":14},{"ref":"Job 28:15","short":"Job 28:15","text":"It cannot be bought for gold, and silver cannot be weighed as its price.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":15},{"ref":"Job 28:16","short":"Job 28:16","text":"It cannot be valued in the gold of Ophir, in precious onyx or sapphire.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":16},{"ref":"Job 28:17","short":"Job 28:17","text":"Gold and glass cannot equal it, nor can it be exchanged for jewels of fine gold.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":17},{"ref":"Job 28:18","short":"Job 28:18","text":"No mention shall be made of coral or of crystal; the price of wisdom is above pearls.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":18},{"ref":"Job 28:19","short":"Job 28:19","text":"The topaz of Ethiopia cannot equal it, nor can it be valued in pure gold.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":19},{"ref":"Job 28:20","short":"Job 28:20","text":"\u201cFrom where, then, does wisdom come? And where is the place of understanding?","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":20},{"ref":"Job 28:21","short":"Job 28:21","text":"It is hidden from the eyes of all living and concealed from the birds of the air.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":21},{"ref":"Job 28:22","short":"Job 28:22","text":"Abaddon and Death say, \u2018We have heard a rumor of it with our ears.\u2019","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":22},{"ref":"Job 28:23","short":"Job 28:23","text":"\u201cGod understands the way to it, and he knows its place.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":23},{"ref":"Job 28:24","short":"Job 28:24","text":"For he looks to the ends of the earth and sees everything under the heavens.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":24},{"ref":"Job 28:25","short":"Job 28:25","text":"When he gave to the wind its weight and apportioned the waters by measure,","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":25},{"ref":"Job 28:26","short":"Job 28:26","text":"when he made a decree for the rain and a way for the lightning of the thunder,","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":26},{"ref":"Job 28:27","short":"Job 28:27","text":"then he saw it and declared it; he established it, and searched it out.","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":27},{"ref":"Job 28:28","short":"Job 28:28","text":"And he said to man, \u2018Behold, the fear of the Lord, that is wisdom, and to turn away from evil is understanding.\u2019\u201d","url":"ot/job/Job_28.html","book":"Job","ch":28,"v":28},{"ref":"Job 29:1","short":"Job 29:1","text":"And Job again took up his discourse, and said:","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":1},{"ref":"Job 29:2","short":"Job 29:2","text":"\u201cOh, that I were as in the months of old, as in the days when God watched over me,","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":2},{"ref":"Job 29:3","short":"Job 29:3","text":"when his lamp shone upon my head, and by his light I walked through darkness,","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":3},{"ref":"Job 29:4","short":"Job 29:4","text":"as I was in my prime, when the friendship of God was upon my tent,","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":4},{"ref":"Job 29:5","short":"Job 29:5","text":"when the Almighty was yet with me, when my children were all around me,","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":5},{"ref":"Job 29:6","short":"Job 29:6","text":"when my steps were washed with butter, and the rock poured out for me streams of oil!","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":6},{"ref":"Job 29:7","short":"Job 29:7","text":"When I went out to the gate of the city, when I prepared my seat in the square,","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":7},{"ref":"Job 29:8","short":"Job 29:8","text":"the young men saw me and withdrew, and the aged rose and stood;","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":8},{"ref":"Job 29:9","short":"Job 29:9","text":"the princes refrained from talking and laid their hand on their mouth;","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":9},{"ref":"Job 29:10","short":"Job 29:10","text":"the voice of the nobles was hushed, and their tongue stuck to the roof of their mouth.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":10},{"ref":"Job 29:11","short":"Job 29:11","text":"When the ear heard, it called me blessed, and when the eye saw, it approved,","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":11},{"ref":"Job 29:12","short":"Job 29:12","text":"because I delivered the poor who cried for help, and the fatherless who had none to help him.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":12},{"ref":"Job 29:13","short":"Job 29:13","text":"The blessing of him who was about to perish came upon me, and I caused the widow\u2019s heart to sing for joy.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":13},{"ref":"Job 29:14","short":"Job 29:14","text":"I put on righteousness, and it clothed me; my justice was like a robe and a turban.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":14},{"ref":"Job 29:15","short":"Job 29:15","text":"I was eyes to the blind and feet to the lame.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":15},{"ref":"Job 29:16","short":"Job 29:16","text":"I was a father to the needy, and I searched out the cause of him whom I did not know.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":16},{"ref":"Job 29:17","short":"Job 29:17","text":"I broke the fangs of the unrighteous and made him drop his prey from his teeth.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":17},{"ref":"Job 29:18","short":"Job 29:18","text":"Then I thought, \u2018I shall die in my nest, and I shall multiply my days as the sand,","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":18},{"ref":"Job 29:19","short":"Job 29:19","text":"my roots spread out to the waters, with the dew all night on my branches,","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":19},{"ref":"Job 29:20","short":"Job 29:20","text":"my glory fresh with me, and my bow ever new in my hand.\u2019","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":20},{"ref":"Job 29:21","short":"Job 29:21","text":"\u201cMen listened to me and waited and kept silence for my counsel.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":21},{"ref":"Job 29:22","short":"Job 29:22","text":"After I spoke they did not speak again, and my word dropped upon them.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":22},{"ref":"Job 29:23","short":"Job 29:23","text":"They waited for me as for the rain, and they opened their mouths as for the spring rain.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":23},{"ref":"Job 29:24","short":"Job 29:24","text":"I smiled on them when they had no confidence, and the light of my face they did not cast down.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":24},{"ref":"Job 29:25","short":"Job 29:25","text":"I chose their way and sat as chief, and I lived like a king among his troops, like one who comforts mourners.","url":"ot/job/Job_29.html","book":"Job","ch":29,"v":25},{"ref":"Job 30:1","short":"Job 30:1","text":"\u201cBut now they laugh at me, men who are younger than I, whose fathers I would have disdained to set with the dogs of my flock.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":1},{"ref":"Job 30:2","short":"Job 30:2","text":"What could I gain from the strength of their hands, men whose vigor is gone?","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":2},{"ref":"Job 30:3","short":"Job 30:3","text":"Through want and hard hunger they gnaw the dry ground by night in waste and desolation;","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":3},{"ref":"Job 30:4","short":"Job 30:4","text":"they pick saltwort and the leaves of bushes, and the roots of the broom tree for their food.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":4},{"ref":"Job 30:5","short":"Job 30:5","text":"They are driven out from human company; they shout after them as after a thief.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":5},{"ref":"Job 30:6","short":"Job 30:6","text":"In the gullies of the torrents they must dwell, in holes of the earth and of the rocks.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":6},{"ref":"Job 30:7","short":"Job 30:7","text":"Among the bushes they bray; under the nettles they huddle together.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":7},{"ref":"Job 30:8","short":"Job 30:8","text":"A senseless, a nameless brood, they have been whipped out of the land.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":8},{"ref":"Job 30:9","short":"Job 30:9","text":"\u201cAnd now I have become their song; I am a byword to them.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":9},{"ref":"Job 30:10","short":"Job 30:10","text":"They abhor me; they keep aloof from me; they do not hesitate to spit at the sight of me.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":10},{"ref":"Job 30:11","short":"Job 30:11","text":"Because God has loosed my cord and humbled me, they have cast off restraint in my presence.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":11},{"ref":"Job 30:12","short":"Job 30:12","text":"On my right hand the rabble rise; they push away my feet; they cast up against me their ways of destruction.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":12},{"ref":"Job 30:13","short":"Job 30:13","text":"They break up my path; they promote my calamity; they need no one to help them.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":13},{"ref":"Job 30:14","short":"Job 30:14","text":"As through a wide breach they come; amid the crash they roll on.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":14},{"ref":"Job 30:15","short":"Job 30:15","text":"Terrors are turned upon me; my honor is pursued as by the wind, and my prosperity has passed away like a cloud.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":15},{"ref":"Job 30:16","short":"Job 30:16","text":"\u201cAnd now my soul is poured out within me; days of affliction have taken hold of me.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":16},{"ref":"Job 30:17","short":"Job 30:17","text":"The night racks my bones, and the pain that gnaws me takes no rest.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":17},{"ref":"Job 30:18","short":"Job 30:18","text":"With great force my garment is disfigured; it binds me about like the collar of my tunic.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":18},{"ref":"Job 30:19","short":"Job 30:19","text":"God has cast me into the mire, and I have become like dust and ashes.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":19},{"ref":"Job 30:20","short":"Job 30:20","text":"I cry to you for help and you do not answer me; I stand, and you only look at me.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":20},{"ref":"Job 30:21","short":"Job 30:21","text":"You have turned cruel to me; with the might of your hand you persecute me.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":21},{"ref":"Job 30:22","short":"Job 30:22","text":"You lift me up on the wind; you make me ride on it, and you toss me about in the roar of the storm.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":22},{"ref":"Job 30:23","short":"Job 30:23","text":"For I know that you will bring me to death and to the house appointed for all living.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":23},{"ref":"Job 30:24","short":"Job 30:24","text":"\u201cYet does not one in a heap of ruins stretch out his hand, and in his disaster cry for help?","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":24},{"ref":"Job 30:25","short":"Job 30:25","text":"Did not I weep for him whose day was hard? Was not my soul grieved for the needy?","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":25},{"ref":"Job 30:26","short":"Job 30:26","text":"But when I hoped for good, evil came, and when I waited for light, darkness came.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":26},{"ref":"Job 30:27","short":"Job 30:27","text":"My inward parts are in turmoil and never still; days of affliction come to meet me.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":27},{"ref":"Job 30:28","short":"Job 30:28","text":"I go about darkened, but not by the sun; I stand up in the assembly and cry for help.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":28},{"ref":"Job 30:29","short":"Job 30:29","text":"I am a brother of jackals and a companion of ostriches.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":29},{"ref":"Job 30:30","short":"Job 30:30","text":"My skin turns black and falls from me, and my bones burn with heat.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":30},{"ref":"Job 30:31","short":"Job 30:31","text":"My lyre is turned to mourning, and my pipe to the voice of those who weep.","url":"ot/job/Job_30.html","book":"Job","ch":30,"v":31},{"ref":"Job 31:1","short":"Job 31:1","text":"\u201cI have made a covenant with my eyes; how then could I gaze at a virgin?","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":1},{"ref":"Job 31:2","short":"Job 31:2","text":"What would be my portion from God above and my heritage from the Almighty on high?","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":2},{"ref":"Job 31:3","short":"Job 31:3","text":"Is not calamity for the unrighteous, and disaster for the workers of iniquity?","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":3},{"ref":"Job 31:4","short":"Job 31:4","text":"Does not he see my ways and number all my steps?","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":4},{"ref":"Job 31:5","short":"Job 31:5","text":"\u201cIf I have walked with falsehood and my foot has hastened to deceit;","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":5},{"ref":"Job 31:6","short":"Job 31:6","text":"(Let me be weighed in a just balance, and let God know my integrity!)","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":6},{"ref":"Job 31:7","short":"Job 31:7","text":"if my step has turned aside from the way and my heart has gone after my eyes, and if any spot has stuck to my hands,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":7},{"ref":"Job 31:8","short":"Job 31:8","text":"then let me sow, and another eat, and let what grows for me be rooted out.","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":8},{"ref":"Job 31:9","short":"Job 31:9","text":"\u201cIf my heart has been enticed toward a woman, and I have lain in wait at my neighbor\u2019s door,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":9},{"ref":"Job 31:10","short":"Job 31:10","text":"then let my wife grind for another, and let others bow down on her.","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":10},{"ref":"Job 31:11","short":"Job 31:11","text":"For that would be a heinous crime; that would be an iniquity to be punished by the judges;","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":11},{"ref":"Job 31:12","short":"Job 31:12","text":"for that would be a fire that consumes as far as Abaddon, and it would burn to the root all my increase.","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":12},{"ref":"Job 31:13","short":"Job 31:13","text":"\u201cIf I have rejected the cause of my manservant or my maidservant, when they brought a complaint against me,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":13},{"ref":"Job 31:14","short":"Job 31:14","text":"what then shall I do when God rises up? When he makes inquiry, what shall I answer him?","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":14},{"ref":"Job 31:15","short":"Job 31:15","text":"Did not he who made me in the womb make him? And did not one fashion us in the womb?","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":15},{"ref":"Job 31:16","short":"Job 31:16","text":"\u201cIf I have withheld anything that the poor desired, or have caused the eyes of the widow to fail,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":16},{"ref":"Job 31:17","short":"Job 31:17","text":"or have eaten my morsel alone, and the fatherless has not eaten of it","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":17},{"ref":"Job 31:18","short":"Job 31:18","text":"(for from my youth the fatherless grew up with me as with a father, and from my mother\u2019s womb I guided the widow),","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":18},{"ref":"Job 31:19","short":"Job 31:19","text":"if I have seen anyone perish for lack of clothing, or the needy without covering,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":19},{"ref":"Job 31:20","short":"Job 31:20","text":"if his body has not blessed me, and if he was not warmed with the fleece of my sheep,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":20},{"ref":"Job 31:21","short":"Job 31:21","text":"if I have raised my hand against the fatherless, because I saw my help in the gate,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":21},{"ref":"Job 31:22","short":"Job 31:22","text":"then let my shoulder blade fall from my shoulder, and let my arm be broken from its socket.","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":22},{"ref":"Job 31:23","short":"Job 31:23","text":"For I was in terror of calamity from God, and I could not have faced his majesty.","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":23},{"ref":"Job 31:24","short":"Job 31:24","text":"\u201cIf I have made gold my trust or called fine gold my confidence,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":24},{"ref":"Job 31:25","short":"Job 31:25","text":"if I have rejoiced because my wealth was abundant or because my hand had found much,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":25},{"ref":"Job 31:26","short":"Job 31:26","text":"if I have looked at the sun when it shone, or the moon moving in splendor,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":26},{"ref":"Job 31:27","short":"Job 31:27","text":"and my heart has been secretly enticed, and my mouth has kissed my hand,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":27},{"ref":"Job 31:28","short":"Job 31:28","text":"this also would be an iniquity to be punished by the judges, for I would have been false to God above.","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":28},{"ref":"Job 31:29","short":"Job 31:29","text":"\u201cIf I have rejoiced at the ruin of him who hated me, or exulted when evil overtook him","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":29},{"ref":"Job 31:30","short":"Job 31:30","text":"(I have not let my mouth sin by asking for his life with a curse),","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":30},{"ref":"Job 31:31","short":"Job 31:31","text":"if the men of my tent have not said, \u2018Who is there that has not been filled with his meat?\u2019","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":31},{"ref":"Job 31:32","short":"Job 31:32","text":"(the sojourner has not lodged in the street; I have opened my doors to the traveler),","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":32},{"ref":"Job 31:33","short":"Job 31:33","text":"if I have concealed my transgressions as others do by hiding my iniquity in my heart,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":33},{"ref":"Job 31:34","short":"Job 31:34","text":"because I stood in great fear of the multitude, and the contempt of families terrified me, so that I kept silence, and did not go out of doors\u2014","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":34},{"ref":"Job 31:35","short":"Job 31:35","text":"Oh, that I had one to hear me! (Here is my signature! Let the Almighty answer me!) Oh, that I had the indictment written by my adversary!","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":35},{"ref":"Job 31:36","short":"Job 31:36","text":"Surely I would carry it on my shoulder; I would bind it on me as a crown;","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":36},{"ref":"Job 31:37","short":"Job 31:37","text":"I would give him an account of all my steps; like a prince I would approach him.","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":37},{"ref":"Job 31:38","short":"Job 31:38","text":"\u201cIf my land has cried out against me and its furrows have wept together,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":38},{"ref":"Job 31:39","short":"Job 31:39","text":"if I have eaten its yield without payment and made its owners breathe their last,","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":39},{"ref":"Job 31:40","short":"Job 31:40","text":"let thorns grow instead of wheat, and foul weeds instead of barley.\u201d The words of Job are ended.","url":"ot/job/Job_31.html","book":"Job","ch":31,"v":40},{"ref":"Job 32:1","short":"Job 32:1","text":"So these three men ceased to answer Job, because he was righteous in his own eyes.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":1},{"ref":"Job 32:2","short":"Job 32:2","text":"Then Elihu the son of Barachel the Buzite, of the family of Ram, burned with anger. He burned with anger at Job because he justified himself rather than God.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":2},{"ref":"Job 32:3","short":"Job 32:3","text":"He burned with anger also at Job\u2019s three friends because they had found no answer, although they had declared Job to be in the wrong.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":3},{"ref":"Job 32:4","short":"Job 32:4","text":"Now Elihu had waited to speak to Job because they were older than he.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":4},{"ref":"Job 32:5","short":"Job 32:5","text":"And when Elihu saw that there was no answer in the mouth of these three men, he burned with anger.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":5},{"ref":"Job 32:6","short":"Job 32:6","text":"And Elihu the son of Barachel the Buzite answered and said: \u201cI am young in years, and you are aged; therefore I was timid and afraid to declare my opinion to you.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":6},{"ref":"Job 32:7","short":"Job 32:7","text":"I said, \u2018Let days speak, and many years teach wisdom.\u2019","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":7},{"ref":"Job 32:8","short":"Job 32:8","text":"But it is the spirit in man, the breath of the Almighty, that makes him understand.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":8},{"ref":"Job 32:9","short":"Job 32:9","text":"It is not the old who are wise, nor the aged who understand what is right.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":9},{"ref":"Job 32:10","short":"Job 32:10","text":"Therefore I say, \u2018Listen to me; let me also declare my opinion.\u2019","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":10},{"ref":"Job 32:11","short":"Job 32:11","text":"\u201cBehold, I waited for your words, I listened for your wise sayings, while you searched out what to say.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":11},{"ref":"Job 32:12","short":"Job 32:12","text":"I gave you my attention, and, behold, there was none among you who refuted Job or who answered his words.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":12},{"ref":"Job 32:13","short":"Job 32:13","text":"Beware lest you say, \u2018We have found wisdom; God may vanquish him, not a man.\u2019","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":13},{"ref":"Job 32:14","short":"Job 32:14","text":"He has not directed his words against me, and I will not answer him with your speeches.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":14},{"ref":"Job 32:15","short":"Job 32:15","text":"\u201cThey are dismayed; they answer no more; they have not a word to say.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":15},{"ref":"Job 32:16","short":"Job 32:16","text":"And shall I wait, because they do not speak, because they stand there, and answer no more?","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":16},{"ref":"Job 32:17","short":"Job 32:17","text":"I also will answer with my share; I also will declare my opinion.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":17},{"ref":"Job 32:18","short":"Job 32:18","text":"For I am full of words; the spirit within me constrains me.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":18},{"ref":"Job 32:19","short":"Job 32:19","text":"Behold, my belly is like wine that has no vent; like new wineskins ready to burst.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":19},{"ref":"Job 32:20","short":"Job 32:20","text":"I must speak, that I may find relief; I must open my lips and answer.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":20},{"ref":"Job 32:21","short":"Job 32:21","text":"I will not show partiality to any man or use flattery toward any person.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":21},{"ref":"Job 32:22","short":"Job 32:22","text":"For I do not know how to flatter, else my Maker would soon take me away.","url":"ot/job/Job_32.html","book":"Job","ch":32,"v":22},{"ref":"Job 33:1","short":"Job 33:1","text":"\u201cBut now, hear my speech, O Job, and listen to all my words.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":1},{"ref":"Job 33:2","short":"Job 33:2","text":"Behold, I open my mouth; the tongue in my mouth speaks.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":2},{"ref":"Job 33:3","short":"Job 33:3","text":"My words declare the uprightness of my heart, and what my lips know they speak sincerely.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":3},{"ref":"Job 33:4","short":"Job 33:4","text":"The Spirit of God has made me, and the breath of the Almighty gives me life.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":4},{"ref":"Job 33:5","short":"Job 33:5","text":"Answer me, if you can; set your words in order before me; take your stand.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":5},{"ref":"Job 33:6","short":"Job 33:6","text":"Behold, I am toward God as you are; I too was pinched off from a piece of clay.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":6},{"ref":"Job 33:7","short":"Job 33:7","text":"Behold, no fear of me need terrify you; my pressure will not be heavy upon you.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":7},{"ref":"Job 33:8","short":"Job 33:8","text":"\u201cSurely you have spoken in my ears, and I have heard the sound of your words.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":8},{"ref":"Job 33:9","short":"Job 33:9","text":"You say, \u2018I am pure, without transgression; I am clean, and there is no iniquity in me.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":9},{"ref":"Job 33:10","short":"Job 33:10","text":"Behold, he finds occasions against me, he counts me as his enemy,","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":10},{"ref":"Job 33:11","short":"Job 33:11","text":"he puts my feet in the stocks and watches all my paths.\u2019","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":11},{"ref":"Job 33:12","short":"Job 33:12","text":"\u201cBehold, in this you are not right. I will answer you, for God is greater than man.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":12},{"ref":"Job 33:13","short":"Job 33:13","text":"Why do you contend against him, saying, \u2018He will answer none of man\u2019s words\u2019?","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":13},{"ref":"Job 33:14","short":"Job 33:14","text":"For God speaks in one way, and in two, though man does not perceive it.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":14},{"ref":"Job 33:15","short":"Job 33:15","text":"In a dream, in a vision of the night, when deep sleep falls on men, while they slumber on their beds,","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":15},{"ref":"Job 33:16","short":"Job 33:16","text":"then he opens the ears of men and terrifies them with warnings,","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":16},{"ref":"Job 33:17","short":"Job 33:17","text":"that he may turn man aside from his deed and conceal pride from a man;","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":17},{"ref":"Job 33:18","short":"Job 33:18","text":"he keeps back his soul from the pit, his life from perishing by the sword.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":18},{"ref":"Job 33:19","short":"Job 33:19","text":"\u201cMan is also rebuked with pain on his bed and with continual strife in his bones,","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":19},{"ref":"Job 33:20","short":"Job 33:20","text":"so that his life loathes bread, and his appetite the choicest food.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":20},{"ref":"Job 33:21","short":"Job 33:21","text":"His flesh is so wasted away that it cannot be seen, and his bones that were not seen stick out.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":21},{"ref":"Job 33:22","short":"Job 33:22","text":"His soul draws near the pit, and his life to those who bring death.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":22},{"ref":"Job 33:23","short":"Job 33:23","text":"If there be for him an angel, a mediator, one of the thousand, to declare to man what is right for him,","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":23},{"ref":"Job 33:24","short":"Job 33:24","text":"and he is merciful to him, and says, \u2018Deliver him from going down into the pit; I have found a ransom;","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":24},{"ref":"Job 33:25","short":"Job 33:25","text":"let his flesh become fresh with youth; let him return to the days of his youthful vigor\u2019;","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":25},{"ref":"Job 33:26","short":"Job 33:26","text":"then man prays to God, and he accepts him; he sees his face with a shout of joy, and he restores to man his righteousness.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":26},{"ref":"Job 33:27","short":"Job 33:27","text":"He sings before men and says: \u2018I sinned and perverted what was right, and it was not repaid to me.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":27},{"ref":"Job 33:28","short":"Job 33:28","text":"He has redeemed my soul from going down into the pit, and my life shall look upon the light.\u2019","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":28},{"ref":"Job 33:29","short":"Job 33:29","text":"\u201cBehold, God does all these things, twice, three times, with a man,","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":29},{"ref":"Job 33:30","short":"Job 33:30","text":"to bring back his soul from the pit, that he may be lighted with the light of life.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":30},{"ref":"Job 33:31","short":"Job 33:31","text":"Pay attention, O Job, listen to me; be silent, and I will speak.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":31},{"ref":"Job 33:32","short":"Job 33:32","text":"If you have any words, answer me; speak, for I desire to justify you.","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":32},{"ref":"Job 33:33","short":"Job 33:33","text":"If not, listen to me; be silent, and I will teach you wisdom.\u201d","url":"ot/job/Job_33.html","book":"Job","ch":33,"v":33},{"ref":"Job 34:1","short":"Job 34:1","text":"Then Elihu answered and said:","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":1},{"ref":"Job 34:2","short":"Job 34:2","text":"\u201cHear my words, you wise men, and give ear to me, you who know;","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":2},{"ref":"Job 34:3","short":"Job 34:3","text":"for the ear tests words as the palate tastes food.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":3},{"ref":"Job 34:4","short":"Job 34:4","text":"Let us choose what is right; let us know among ourselves what is good.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":4},{"ref":"Job 34:5","short":"Job 34:5","text":"For Job has said, \u2018I am in the right, and God has taken away my right;","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":5},{"ref":"Job 34:6","short":"Job 34:6","text":"in spite of my right I am counted a liar; my wound is incurable, though I am without transgression.\u2019","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":6},{"ref":"Job 34:7","short":"Job 34:7","text":"What man is like Job, who drinks up scoffing like water,","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":7},{"ref":"Job 34:8","short":"Job 34:8","text":"who travels in company with evildoers and walks with wicked men?","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":8},{"ref":"Job 34:9","short":"Job 34:9","text":"For he has said, \u2018It profits a man nothing that he should take delight in God.\u2019","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":9},{"ref":"Job 34:10","short":"Job 34:10","text":"\u201cTherefore, hear me, you men of understanding: far be it from God that he should do wickedness, and from the Almighty that he should do wrong.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":10},{"ref":"Job 34:11","short":"Job 34:11","text":"For according to the work of a man he will repay him, and according to his ways he will make it befall him.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":11},{"ref":"Job 34:12","short":"Job 34:12","text":"Of a truth, God will not do wickedly, and the Almighty will not pervert justice.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":12},{"ref":"Job 34:13","short":"Job 34:13","text":"Who gave him charge over the earth, and who laid on him the whole world?","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":13},{"ref":"Job 34:14","short":"Job 34:14","text":"If he should set his heart to it and gather to himself his spirit and his breath,","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":14},{"ref":"Job 34:15","short":"Job 34:15","text":"all flesh would perish together, and man would return to dust.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":15},{"ref":"Job 34:16","short":"Job 34:16","text":"\u201cIf you have understanding, hear this; listen to what I say.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":16},{"ref":"Job 34:17","short":"Job 34:17","text":"Shall one who hates justice govern? Will you condemn him who is righteous and mighty,","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":17},{"ref":"Job 34:18","short":"Job 34:18","text":"who says to a king, \u2018Worthless one,\u2019 and to nobles, \u2018Wicked man,\u2019","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":18},{"ref":"Job 34:19","short":"Job 34:19","text":"who shows no partiality to princes, nor regards the rich more than the poor, for they are all the work of his hands?","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":19},{"ref":"Job 34:20","short":"Job 34:20","text":"In a moment they die; at midnight the people are shaken and pass away, and the mighty are taken away by no human hand.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":20},{"ref":"Job 34:21","short":"Job 34:21","text":"\u201cFor his eyes are on the ways of a man, and he sees all his steps.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":21},{"ref":"Job 34:22","short":"Job 34:22","text":"There is no gloom or deep darkness where evildoers may hide themselves.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":22},{"ref":"Job 34:23","short":"Job 34:23","text":"For God has no need to consider a man further, that he should go before God in judgment.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":23},{"ref":"Job 34:24","short":"Job 34:24","text":"He shatters the mighty without investigation and sets others in their place.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":24},{"ref":"Job 34:25","short":"Job 34:25","text":"Thus, knowing their works, he overturns them in the night, and they are crushed.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":25},{"ref":"Job 34:26","short":"Job 34:26","text":"He strikes them for their wickedness in a place for all to see,","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":26},{"ref":"Job 34:27","short":"Job 34:27","text":"because they turned aside from following him and had no regard for any of his ways,","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":27},{"ref":"Job 34:28","short":"Job 34:28","text":"so that they caused the cry of the poor to come to him, and he heard the cry of the afflicted\u2014","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":28},{"ref":"Job 34:29","short":"Job 34:29","text":"When he is quiet, who can condemn? When he hides his face, who can behold him, whether it be a nation or a man?\u2014","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":29},{"ref":"Job 34:30","short":"Job 34:30","text":"that a godless man should not reign, that he should not ensnare the people.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":30},{"ref":"Job 34:31","short":"Job 34:31","text":"\u201cFor has anyone said to God, \u2018I have borne punishment; I will not offend any more;","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":31},{"ref":"Job 34:32","short":"Job 34:32","text":"teach me what I do not see; if I have done iniquity, I will do it no more\u2019?","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":32},{"ref":"Job 34:33","short":"Job 34:33","text":"Will he then make repayment to suit you, because you reject it? For you must choose, and not I; therefore declare what you know.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":33},{"ref":"Job 34:34","short":"Job 34:34","text":"Men of understanding will say to me, and the wise man who hears me will say:","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":34},{"ref":"Job 34:35","short":"Job 34:35","text":"\u2018Job speaks without knowledge; his words are without insight.\u2019","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":35},{"ref":"Job 34:36","short":"Job 34:36","text":"Would that Job were tried to the end, because he answers like wicked men.","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":36},{"ref":"Job 34:37","short":"Job 34:37","text":"For he adds rebellion to his sin; he claps his hands among us and multiplies his words against God.\u201d","url":"ot/job/Job_34.html","book":"Job","ch":34,"v":37},{"ref":"Job 35:1","short":"Job 35:1","text":"And Elihu answered and said:","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":1},{"ref":"Job 35:2","short":"Job 35:2","text":"\u201cDo you think this to be just? Do you say, \u2018It is my right before God,\u2019","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":2},{"ref":"Job 35:3","short":"Job 35:3","text":"that you ask, \u2018What advantage have I? How am I better off than if I had sinned?\u2019","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":3},{"ref":"Job 35:4","short":"Job 35:4","text":"I will answer you and your friends with you.","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":4},{"ref":"Job 35:5","short":"Job 35:5","text":"Look at the heavens, and see; and behold the clouds, which are higher than you.","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":5},{"ref":"Job 35:6","short":"Job 35:6","text":"If you have sinned, what do you accomplish against him? And if your transgressions are multiplied, what do you do to him?","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":6},{"ref":"Job 35:7","short":"Job 35:7","text":"If you are righteous, what do you give to him? Or what does he receive from your hand?","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":7},{"ref":"Job 35:8","short":"Job 35:8","text":"Your wickedness concerns a man like yourself, and your righteousness a son of man.","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":8},{"ref":"Job 35:9","short":"Job 35:9","text":"\u201cBecause of the multitude of oppressions people cry out; they call for help because of the arm of the mighty.","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":9},{"ref":"Job 35:10","short":"Job 35:10","text":"But none says, \u2018Where is God my Maker, who gives songs in the night,","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":10},{"ref":"Job 35:11","short":"Job 35:11","text":"who teaches us more than the beasts of the earth and makes us wiser than the birds of the heavens?\u2019","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":11},{"ref":"Job 35:12","short":"Job 35:12","text":"There they cry out, but he does not answer, because of the pride of evil men.","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":12},{"ref":"Job 35:13","short":"Job 35:13","text":"Surely God does not hear an empty cry, nor does the Almighty regard it.","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":13},{"ref":"Job 35:14","short":"Job 35:14","text":"How much less when you say that you do not see him, that the case is before him, and you are waiting for him!","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":14},{"ref":"Job 35:15","short":"Job 35:15","text":"And now, because his anger does not punish, and he does not take much note of transgression,","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":15},{"ref":"Job 35:16","short":"Job 35:16","text":"Job opens his mouth in empty talk; he multiplies words without knowledge.\u201d","url":"ot/job/Job_35.html","book":"Job","ch":35,"v":16},{"ref":"Job 36:1","short":"Job 36:1","text":"And Elihu continued, and said:","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":1},{"ref":"Job 36:2","short":"Job 36:2","text":"\u201cBear with me a little, and I will show you, for I have yet something to say on God\u2019s behalf.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":2},{"ref":"Job 36:3","short":"Job 36:3","text":"I will get my knowledge from afar and ascribe righteousness to my Maker.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":3},{"ref":"Job 36:4","short":"Job 36:4","text":"For truly my words are not false; one who is perfect in knowledge is with you.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":4},{"ref":"Job 36:5","short":"Job 36:5","text":"\u201cBehold, God is mighty, and does not despise any; he is mighty in strength of understanding.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":5},{"ref":"Job 36:6","short":"Job 36:6","text":"He does not keep the wicked alive, but gives the afflicted their right.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":6},{"ref":"Job 36:7","short":"Job 36:7","text":"He does not withdraw his eyes from the righteous, but with kings on the throne he sets them forever, and they are exalted.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":7},{"ref":"Job 36:8","short":"Job 36:8","text":"And if they are bound in chains and caught in the cords of affliction,","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":8},{"ref":"Job 36:9","short":"Job 36:9","text":"then he declares to them their work and their transgressions, that they are behaving arrogantly.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":9},{"ref":"Job 36:10","short":"Job 36:10","text":"He opens their ears to instruction and commands that they return from iniquity.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":10},{"ref":"Job 36:11","short":"Job 36:11","text":"If they listen and serve him, they complete their days in prosperity, and their years in pleasantness.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":11},{"ref":"Job 36:12","short":"Job 36:12","text":"But if they do not listen, they perish by the sword and die without knowledge.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":12},{"ref":"Job 36:13","short":"Job 36:13","text":"\u201cThe godless in heart cherish anger; they do not cry for help when he binds them.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":13},{"ref":"Job 36:14","short":"Job 36:14","text":"They die in youth, and their life ends among the cult prostitutes.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":14},{"ref":"Job 36:15","short":"Job 36:15","text":"He delivers the afflicted by their affliction and opens their ear by adversity.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":15},{"ref":"Job 36:16","short":"Job 36:16","text":"He also allured you out of distress into a broad place where there was no cramping, and what was set on your table was full of fatness.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":16},{"ref":"Job 36:17","short":"Job 36:17","text":"\u201cBut you are full of the judgment on the wicked; judgment and justice seize you.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":17},{"ref":"Job 36:18","short":"Job 36:18","text":"Beware lest wrath entice you into scoffing, and let not the greatness of the ransom turn you aside.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":18},{"ref":"Job 36:19","short":"Job 36:19","text":"Will your cry for help avail to keep you from distress, or all the force of your strength?","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":19},{"ref":"Job 36:20","short":"Job 36:20","text":"Do not long for the night, when peoples vanish in their place.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":20},{"ref":"Job 36:21","short":"Job 36:21","text":"Take care; do not turn to iniquity, for this you have chosen rather than affliction.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":21},{"ref":"Job 36:22","short":"Job 36:22","text":"Behold, God is exalted in his power; who is a teacher like him?","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":22},{"ref":"Job 36:23","short":"Job 36:23","text":"Who has prescribed for him his way, or who can say, \u2018You have done wrong\u2019?","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":23},{"ref":"Job 36:24","short":"Job 36:24","text":"\u201cRemember to extol his work, of which men have sung.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":24},{"ref":"Job 36:25","short":"Job 36:25","text":"All mankind has looked on it; man beholds it from afar.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":25},{"ref":"Job 36:26","short":"Job 36:26","text":"Behold, God is great, and we know him not; the number of his years is unsearchable.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":26},{"ref":"Job 36:27","short":"Job 36:27","text":"For he draws up the drops of water; they distill his mist in rain,","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":27},{"ref":"Job 36:28","short":"Job 36:28","text":"which the skies pour down and drop on mankind abundantly.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":28},{"ref":"Job 36:29","short":"Job 36:29","text":"Can anyone understand the spreading of the clouds, the thunderings of his pavilion?","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":29},{"ref":"Job 36:30","short":"Job 36:30","text":"Behold, he scatters his lightning about him and covers the roots of the sea.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":30},{"ref":"Job 36:31","short":"Job 36:31","text":"For by these he judges peoples; he gives food in abundance.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":31},{"ref":"Job 36:32","short":"Job 36:32","text":"He covers his hands with the lightning and commands it to strike the mark.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":32},{"ref":"Job 36:33","short":"Job 36:33","text":"Its crashing declares his presence; the cattle also declare that he rises.","url":"ot/job/Job_36.html","book":"Job","ch":36,"v":33},{"ref":"Job 37:1","short":"Job 37:1","text":"\u201cAt this also my heart trembles and leaps out of its place.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":1},{"ref":"Job 37:2","short":"Job 37:2","text":"Keep listening to the thunder of his voice and the rumbling that comes from his mouth.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":2},{"ref":"Job 37:3","short":"Job 37:3","text":"Under the whole heaven he lets it go, and his lightning to the corners of the earth.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":3},{"ref":"Job 37:4","short":"Job 37:4","text":"After it his voice roars; he thunders with his majestic voice, and he does not restrain the lightnings when his voice is heard.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":4},{"ref":"Job 37:5","short":"Job 37:5","text":"God thunders wondrously with his voice; he does great things that we cannot comprehend.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":5},{"ref":"Job 37:6","short":"Job 37:6","text":"For to the snow he says, \u2018Fall on the earth,\u2019 likewise to the downpour, his mighty downpour.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":6},{"ref":"Job 37:7","short":"Job 37:7","text":"He seals up the hand of every man, that all men whom he made may know it.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":7},{"ref":"Job 37:8","short":"Job 37:8","text":"Then the beasts go into their lairs, and remain in their dens.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":8},{"ref":"Job 37:9","short":"Job 37:9","text":"From its chamber comes the whirlwind, and cold from the scattering winds.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":9},{"ref":"Job 37:10","short":"Job 37:10","text":"By the breath of God ice is given, and the broad waters are frozen fast.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":10},{"ref":"Job 37:11","short":"Job 37:11","text":"He loads the thick cloud with moisture; the clouds scatter his lightning.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":11},{"ref":"Job 37:12","short":"Job 37:12","text":"They turn around and around by his guidance, to accomplish all that he commands them on the face of the habitable world.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":12},{"ref":"Job 37:13","short":"Job 37:13","text":"Whether for correction or for his land or for love, he causes it to happen.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":13},{"ref":"Job 37:14","short":"Job 37:14","text":"\u201cHear this, O Job; stop and consider the wondrous works of God.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":14},{"ref":"Job 37:15","short":"Job 37:15","text":"Do you know how God lays his command upon them and causes the lightning of his cloud to shine?","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":15},{"ref":"Job 37:16","short":"Job 37:16","text":"Do you know the balancings of the clouds, the wondrous works of him who is perfect in knowledge,","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":16},{"ref":"Job 37:17","short":"Job 37:17","text":"you whose garments are hot when the earth is still because of the south wind?","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":17},{"ref":"Job 37:18","short":"Job 37:18","text":"Can you, like him, spread out the skies, hard as a cast metal mirror?","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":18},{"ref":"Job 37:19","short":"Job 37:19","text":"Teach us what we shall say to him; we cannot draw up our case because of darkness.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":19},{"ref":"Job 37:20","short":"Job 37:20","text":"Shall it be told him that I would speak? Did a man ever wish that he would be swallowed up?","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":20},{"ref":"Job 37:21","short":"Job 37:21","text":"\u201cAnd now no one looks on the light when it is bright in the skies, when the wind has passed and cleared them.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":21},{"ref":"Job 37:22","short":"Job 37:22","text":"Out of the north comes golden splendor; God is clothed with awesome majesty.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":22},{"ref":"Job 37:23","short":"Job 37:23","text":"The Almighty\u2014we cannot find him; he is great in power; justice and abundant righteousness he will not violate.","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":23},{"ref":"Job 37:24","short":"Job 37:24","text":"Therefore men fear him; he does not regard any who are wise in their own conceit.\u201d","url":"ot/job/Job_37.html","book":"Job","ch":37,"v":24},{"ref":"Job 38:1","short":"Job 38:1","text":"Then the LORD answered Job out of the whirlwind and said:","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":1},{"ref":"Job 38:2","short":"Job 38:2","text":"\u201cWho is this that darkens counsel by words without knowledge?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":2},{"ref":"Job 38:3","short":"Job 38:3","text":"Dress for action like a man; I will question you, and you make it known to me.","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":3},{"ref":"Job 38:4","short":"Job 38:4","text":"\u201cWhere were you when I laid the foundation of the earth? Tell me, if you have understanding.","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":4},{"ref":"Job 38:5","short":"Job 38:5","text":"Who determined its measurements\u2014surely you know! Or who stretched the line upon it?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":5},{"ref":"Job 38:6","short":"Job 38:6","text":"On what were its bases sunk, or who laid its cornerstone,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":6},{"ref":"Job 38:7","short":"Job 38:7","text":"when the morning stars sang together and all the sons of God shouted for joy?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":7},{"ref":"Job 38:8","short":"Job 38:8","text":"\u201cOr who shut in the sea with doors when it burst out from the womb,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":8},{"ref":"Job 38:9","short":"Job 38:9","text":"when I made clouds its garment and thick darkness its swaddling band,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":9},{"ref":"Job 38:10","short":"Job 38:10","text":"and prescribed limits for it and set bars and doors,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":10},{"ref":"Job 38:11","short":"Job 38:11","text":"and said, \u2018Thus far shall you come, and no farther, and here shall your proud waves be stayed\u2019?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":11},{"ref":"Job 38:12","short":"Job 38:12","text":"\u201cHave you commanded the morning since your days began, and caused the dawn to know its place,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":12},{"ref":"Job 38:13","short":"Job 38:13","text":"that it might take hold of the skirts of the earth, and the wicked be shaken out of it?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":13},{"ref":"Job 38:14","short":"Job 38:14","text":"It is changed like clay under the seal, and its features stand out like a garment.","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":14},{"ref":"Job 38:15","short":"Job 38:15","text":"From the wicked their light is withheld, and their uplifted arm is broken.","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":15},{"ref":"Job 38:16","short":"Job 38:16","text":"\u201cHave you entered into the springs of the sea, or walked in the recesses of the deep?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":16},{"ref":"Job 38:17","short":"Job 38:17","text":"Have the gates of death been revealed to you, or have you seen the gates of deep darkness?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":17},{"ref":"Job 38:18","short":"Job 38:18","text":"Have you comprehended the expanse of the earth? Declare, if you know all this.","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":18},{"ref":"Job 38:19","short":"Job 38:19","text":"\u201cWhere is the way to the dwelling of light, and where is the place of darkness,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":19},{"ref":"Job 38:20","short":"Job 38:20","text":"that you may take it to its territory and that you may discern the paths to its home?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":20},{"ref":"Job 38:21","short":"Job 38:21","text":"You know, for you were born then, and the number of your days is great!","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":21},{"ref":"Job 38:22","short":"Job 38:22","text":"\u201cHave you entered the storehouses of the snow, or have you seen the storehouses of the hail,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":22},{"ref":"Job 38:23","short":"Job 38:23","text":"which I have reserved for the time of trouble, for the day of battle and war?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":23},{"ref":"Job 38:24","short":"Job 38:24","text":"What is the way to the place where the light is distributed, or where the east wind is scattered upon the earth?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":24},{"ref":"Job 38:25","short":"Job 38:25","text":"\u201cWho has cleft a channel for the torrents of rain and a way for the thunderbolt,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":25},{"ref":"Job 38:26","short":"Job 38:26","text":"to bring rain on a land where no man is, on the desert in which there is no man,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":26},{"ref":"Job 38:27","short":"Job 38:27","text":"to satisfy the waste and desolate land, and to make the ground sprout with grass?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":27},{"ref":"Job 38:28","short":"Job 38:28","text":"\u201cHas the rain a father, or who has begotten the drops of dew?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":28},{"ref":"Job 38:29","short":"Job 38:29","text":"From whose womb did the ice come forth, and who has given birth to the frost of heaven?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":29},{"ref":"Job 38:30","short":"Job 38:30","text":"The waters become hard like stone, and the face of the deep is frozen.","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":30},{"ref":"Job 38:31","short":"Job 38:31","text":"\u201cCan you bind the chains of the Pleiades or loose the cords of Orion?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":31},{"ref":"Job 38:32","short":"Job 38:32","text":"Can you lead forth the Mazzaroth in their season, or can you guide the Bear with its children?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":32},{"ref":"Job 38:33","short":"Job 38:33","text":"Do you know the ordinances of the heavens? Can you establish their rule on the earth?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":33},{"ref":"Job 38:34","short":"Job 38:34","text":"\u201cCan you lift up your voice to the clouds, that a flood of waters may cover you?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":34},{"ref":"Job 38:35","short":"Job 38:35","text":"Can you send forth lightnings, that they may go and say to you, \u2018Here we are\u2019?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":35},{"ref":"Job 38:36","short":"Job 38:36","text":"Who has put wisdom in the inward parts or given understanding to the mind?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":36},{"ref":"Job 38:37","short":"Job 38:37","text":"Who can number the clouds by wisdom? Or who can tilt the waterskins of the heavens,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":37},{"ref":"Job 38:38","short":"Job 38:38","text":"when the dust runs into a mass and the clods stick fast together?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":38},{"ref":"Job 38:39","short":"Job 38:39","text":"\u201cCan you hunt the prey for the lion, or satisfy the appetite of the young lions,","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":39},{"ref":"Job 38:40","short":"Job 38:40","text":"when they crouch in their dens or lie in wait in their thicket?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":40},{"ref":"Job 38:41","short":"Job 38:41","text":"Who provides for the raven its prey, when its young ones cry to God for help, and wander about for lack of food?","url":"ot/job/Job_38.html","book":"Job","ch":38,"v":41},{"ref":"Job 39:1","short":"Job 39:1","text":"\u201cDo you know when the mountain goats give birth? Do you observe the calving of the does?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":1},{"ref":"Job 39:2","short":"Job 39:2","text":"Can you number the months that they fulfill, and do you know the time when they give birth,","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":2},{"ref":"Job 39:3","short":"Job 39:3","text":"when they crouch, bring forth their offspring, and are delivered of their young?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":3},{"ref":"Job 39:4","short":"Job 39:4","text":"Their young ones become strong; they grow up in the open; they go out and do not return to them.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":4},{"ref":"Job 39:5","short":"Job 39:5","text":"\u201cWho has let the wild donkey go free? Who has loosed the bonds of the swift donkey,","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":5},{"ref":"Job 39:6","short":"Job 39:6","text":"to whom I have given the arid plain for his home and the salt land for his dwelling place?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":6},{"ref":"Job 39:7","short":"Job 39:7","text":"He scorns the tumult of the city; he hears not the shouts of the driver.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":7},{"ref":"Job 39:8","short":"Job 39:8","text":"He ranges the mountains as his pasture, and he searches after every green thing.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":8},{"ref":"Job 39:9","short":"Job 39:9","text":"\u201cIs the wild ox willing to serve you? Will he spend the night at your manger?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":9},{"ref":"Job 39:10","short":"Job 39:10","text":"Can you bind him in the furrow with ropes, or will he harrow the valleys after you?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":10},{"ref":"Job 39:11","short":"Job 39:11","text":"Will you depend on him because his strength is great, and will you leave to him your labor?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":11},{"ref":"Job 39:12","short":"Job 39:12","text":"Do you have faith in him that he will return your grain and gather it to your threshing floor?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":12},{"ref":"Job 39:13","short":"Job 39:13","text":"\u201cThe wings of the ostrich wave proudly, but are they the pinions and plumage of love?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":13},{"ref":"Job 39:14","short":"Job 39:14","text":"For she leaves her eggs to the earth and lets them be warmed on the ground,","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":14},{"ref":"Job 39:15","short":"Job 39:15","text":"forgetting that a foot may crush them and that the wild beast may trample them.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":15},{"ref":"Job 39:16","short":"Job 39:16","text":"She deals cruelly with her young, as if they were not hers; though her labor be in vain, yet she has no fear,","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":16},{"ref":"Job 39:17","short":"Job 39:17","text":"because God has made her forget wisdom and given her no share in understanding.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":17},{"ref":"Job 39:18","short":"Job 39:18","text":"When she rouses herself to flee, she laughs at the horse and his rider.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":18},{"ref":"Job 39:19","short":"Job 39:19","text":"\u201cDo you give the horse his might? Do you clothe his neck with a mane?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":19},{"ref":"Job 39:20","short":"Job 39:20","text":"Do you make him leap like the locust? His majestic snorting is terrifying.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":20},{"ref":"Job 39:21","short":"Job 39:21","text":"He paws in the valley and exults in his strength; he goes out to meet the weapons.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":21},{"ref":"Job 39:22","short":"Job 39:22","text":"He laughs at fear and is not dismayed; he does not turn back from the sword.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":22},{"ref":"Job 39:23","short":"Job 39:23","text":"Upon him rattle the quiver, the flashing spear, and the javelin.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":23},{"ref":"Job 39:24","short":"Job 39:24","text":"With fierceness and rage he swallows the ground; he cannot stand still at the sound of the trumpet.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":24},{"ref":"Job 39:25","short":"Job 39:25","text":"When the trumpet sounds, he says \u2018Aha!\u2019 He smells the battle from afar, the thunder of the captains, and the shouting.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":25},{"ref":"Job 39:26","short":"Job 39:26","text":"\u201cIs it by your understanding that the hawk soars and spreads his wings toward the south?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":26},{"ref":"Job 39:27","short":"Job 39:27","text":"Is it at your command that the eagle mounts up and makes his nest on high?","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":27},{"ref":"Job 39:28","short":"Job 39:28","text":"On the rock he dwells and makes his home, on the rocky crag and stronghold.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":28},{"ref":"Job 39:29","short":"Job 39:29","text":"From there he spies out the prey; his eyes behold it from far away.","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":29},{"ref":"Job 39:30","short":"Job 39:30","text":"His young ones suck up blood, and where the slain are, there is he.\u201d","url":"ot/job/Job_39.html","book":"Job","ch":39,"v":30},{"ref":"Job 40:1","short":"Job 40:1","text":"And the LORD said to Job:","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":1},{"ref":"Job 40:2","short":"Job 40:2","text":"\u201cShall a faultfinder contend with the Almighty? He who argues with God, let him answer it.\u201d","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":2},{"ref":"Job 40:3","short":"Job 40:3","text":"Then Job answered the LORD and said:","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":3},{"ref":"Job 40:4","short":"Job 40:4","text":"\u201cBehold, I am of small account; what shall I answer you? I lay my hand on my mouth.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":4},{"ref":"Job 40:5","short":"Job 40:5","text":"I have spoken once, and I will not answer; twice, but I will proceed no further.\u201d","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":5},{"ref":"Job 40:6","short":"Job 40:6","text":"Then the LORD answered Job out of the whirlwind and said:","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":6},{"ref":"Job 40:7","short":"Job 40:7","text":"\u201cDress for action like a man; I will question you, and you make it known to me.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":7},{"ref":"Job 40:8","short":"Job 40:8","text":"Will you even put me in the wrong? Will you condemn me that you may be in the right?","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":8},{"ref":"Job 40:9","short":"Job 40:9","text":"Have you an arm like God, and can you thunder with a voice like his?","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":9},{"ref":"Job 40:10","short":"Job 40:10","text":"\u201cAdorn yourself with majesty and dignity; clothe yourself with glory and splendor.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":10},{"ref":"Job 40:11","short":"Job 40:11","text":"Pour out the overflowings of your anger, and look on everyone who is proud and abase him.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":11},{"ref":"Job 40:12","short":"Job 40:12","text":"Look on everyone who is proud and bring him low and tread down the wicked where they stand.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":12},{"ref":"Job 40:13","short":"Job 40:13","text":"Hide them all in the dust together; bind their faces in the world below.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":13},{"ref":"Job 40:14","short":"Job 40:14","text":"Then will I also acknowledge to you that your own right hand can save you.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":14},{"ref":"Job 40:15","short":"Job 40:15","text":"\u201cBehold, Behemoth, which I made as I made you; he eats grass like an ox.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":15},{"ref":"Job 40:16","short":"Job 40:16","text":"Behold, his strength in his loins, and his power in the muscles of his belly.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":16},{"ref":"Job 40:17","short":"Job 40:17","text":"He makes his tail stiff like a cedar; the sinews of his thighs are knit together.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":17},{"ref":"Job 40:18","short":"Job 40:18","text":"His bones are tubes of bronze, his limbs like bars of iron.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":18},{"ref":"Job 40:19","short":"Job 40:19","text":"\u201cHe is the first of the works of God; let him who made him bring near his sword!","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":19},{"ref":"Job 40:20","short":"Job 40:20","text":"For the mountains yield food for him where all the wild beasts play.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":20},{"ref":"Job 40:21","short":"Job 40:21","text":"Under the lotus plants he lies, in the shelter of the reeds and in the marsh.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":21},{"ref":"Job 40:22","short":"Job 40:22","text":"For his shade the lotus trees cover him; the willows of the brook surround him.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":22},{"ref":"Job 40:23","short":"Job 40:23","text":"Behold, if the river is turbulent he is not frightened; he is confident though Jordan rushes against his mouth.","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":23},{"ref":"Job 40:24","short":"Job 40:24","text":"Can one take him by his eyes, or pierce his nose with a snare?","url":"ot/job/Job_40.html","book":"Job","ch":40,"v":24},{"ref":"Job 41:1","short":"Job 41:1","text":"\u201cCan you draw out Leviathan with a fishhook or press down his tongue with a cord?","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":1},{"ref":"Job 41:2","short":"Job 41:2","text":"Can you put a rope in his nose or pierce his jaw with a hook?","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":2},{"ref":"Job 41:3","short":"Job 41:3","text":"Will he make many pleas to you? Will he speak to you soft words?","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":3},{"ref":"Job 41:4","short":"Job 41:4","text":"Will he make a covenant with you to take him for your servant forever?","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":4},{"ref":"Job 41:5","short":"Job 41:5","text":"Will you play with him as with a bird, or will you put him on a leash for your girls?","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":5},{"ref":"Job 41:6","short":"Job 41:6","text":"Will traders bargain over him? Will they divide him up among the merchants?","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":6},{"ref":"Job 41:7","short":"Job 41:7","text":"Can you fill his skin with harpoons or his head with fishing spears?","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":7},{"ref":"Job 41:8","short":"Job 41:8","text":"Lay your hands on him; remember the battle\u2014you will not do it again!","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":8},{"ref":"Job 41:9","short":"Job 41:9","text":"Behold, the hope of a man is false; he is laid low even at the sight of him.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":9},{"ref":"Job 41:10","short":"Job 41:10","text":"No one is so fierce that he dares to stir him up. Who then is he who can stand before me?","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":10},{"ref":"Job 41:11","short":"Job 41:11","text":"Who has first given to me, that I should repay him? Whatever is under the whole heaven is mine.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":11},{"ref":"Job 41:12","short":"Job 41:12","text":"\u201cI will not keep silence concerning his limbs, or his mighty strength, or his goodly frame.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":12},{"ref":"Job 41:13","short":"Job 41:13","text":"Who can strip off his outer garment? Who would come near him with a bridle?","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":13},{"ref":"Job 41:14","short":"Job 41:14","text":"Who can open the doors of his face? Around his teeth is terror.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":14},{"ref":"Job 41:15","short":"Job 41:15","text":"His back is made of rows of shields, shut up closely as with a seal.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":15},{"ref":"Job 41:16","short":"Job 41:16","text":"One is so near to another that no air can come between them.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":16},{"ref":"Job 41:17","short":"Job 41:17","text":"They are joined one to another; they clasp each other and cannot be separated.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":17},{"ref":"Job 41:18","short":"Job 41:18","text":"His sneezings flash forth light, and his eyes are like the eyelids of the dawn.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":18},{"ref":"Job 41:19","short":"Job 41:19","text":"Out of his mouth go flaming torches; sparks of fire leap forth.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":19},{"ref":"Job 41:20","short":"Job 41:20","text":"Out of his nostrils comes forth smoke, as from a boiling pot and burning rushes.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":20},{"ref":"Job 41:21","short":"Job 41:21","text":"His breath kindles coals, and a flame comes forth from his mouth.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":21},{"ref":"Job 41:22","short":"Job 41:22","text":"In his neck abides strength, and terror dances before him.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":22},{"ref":"Job 41:23","short":"Job 41:23","text":"The folds of his flesh stick together, firmly cast on him and immovable.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":23},{"ref":"Job 41:24","short":"Job 41:24","text":"His heart is hard as a stone, hard as the lower millstone.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":24},{"ref":"Job 41:25","short":"Job 41:25","text":"When he raises himself up, the mighty are afraid; at the crashing they are beside themselves.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":25},{"ref":"Job 41:26","short":"Job 41:26","text":"Though the sword reaches him, it does not avail, nor the spear, the dart, or the javelin.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":26},{"ref":"Job 41:27","short":"Job 41:27","text":"He counts iron as straw, and bronze as rotten wood.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":27},{"ref":"Job 41:28","short":"Job 41:28","text":"The arrow cannot make him flee; for him, sling stones are turned to stubble.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":28},{"ref":"Job 41:29","short":"Job 41:29","text":"Clubs are counted as stubble; he laughs at the rattle of javelins.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":29},{"ref":"Job 41:30","short":"Job 41:30","text":"His underparts are like sharp potsherds; he spreads himself like a threshing sledge on the mire.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":30},{"ref":"Job 41:31","short":"Job 41:31","text":"He makes the deep boil like a pot; he makes the sea like a pot of ointment.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":31},{"ref":"Job 41:32","short":"Job 41:32","text":"Behind him he leaves a shining wake; one would think the deep to be white-haired.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":32},{"ref":"Job 41:33","short":"Job 41:33","text":"On earth there is not his like, a creature without fear.","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":33},{"ref":"Job 41:34","short":"Job 41:34","text":"He sees everything that is high; he is king over all the sons of pride.\u201d","url":"ot/job/Job_41.html","book":"Job","ch":41,"v":34},{"ref":"Job 42:1","short":"Job 42:1","text":"Then Job answered the LORD and said:","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":1},{"ref":"Job 42:2","short":"Job 42:2","text":"\u201cI know that you can do all things, and that no purpose of yours can be thwarted.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":2},{"ref":"Job 42:3","short":"Job 42:3","text":"\u2018Who is this that hides counsel without knowledge?\u2019 Therefore I have uttered what I did not understand, things too wonderful for me, which I did not know.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":3},{"ref":"Job 42:4","short":"Job 42:4","text":"\u2018Hear, and I will speak; I will question you, and you make it known to me.\u2019","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":4},{"ref":"Job 42:5","short":"Job 42:5","text":"I had heard of you by the hearing of the ear, but now my eye sees you;","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":5},{"ref":"Job 42:6","short":"Job 42:6","text":"therefore I despise myself, and repent in dust and ashes.\u201d","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":6},{"ref":"Job 42:7","short":"Job 42:7","text":"After the LORD had spoken these words to Job, the LORD said to Eliphaz the Temanite: \u201cMy anger burns against you and against your two friends, for you have not spoken of me what is right, as my servant Job has.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":7},{"ref":"Job 42:8","short":"Job 42:8","text":"Now therefore take seven bulls and seven rams and go to my servant Job and offer up a burnt offering for yourselves. And my servant Job shall pray for you, for I will accept his prayer not to deal with you according to your folly. For you have not spoken of me what is right, as my servant Job has.\u201d","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":8},{"ref":"Job 42:9","short":"Job 42:9","text":"So Eliphaz the Temanite and Bildad the Shuhite and Zophar the Naamathite went and did what the LORD had told them, and the LORD accepted Job\u2019s prayer.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":9},{"ref":"Job 42:10","short":"Job 42:10","text":"And the LORD restored the fortunes of Job, when he had prayed for his friends. And the LORD gave Job twice as much as he had before.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":10},{"ref":"Job 42:11","short":"Job 42:11","text":"Then came to him all his brothers and sisters and all who had known him before, and ate bread with him in his house. And they showed him sympathy and comforted him for all the evil that the LORD had brought upon him. And each of them gave him a piece of money and a ring of gold.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":11},{"ref":"Job 42:12","short":"Job 42:12","text":"And the LORD blessed the latter days of Job more than his beginning. And he had 14,000 sheep, 6,000 camels, 1,000 yoke of oxen, and 1,000 female donkeys.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":12},{"ref":"Job 42:13","short":"Job 42:13","text":"He had also seven sons and three daughters.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":13},{"ref":"Job 42:14","short":"Job 42:14","text":"And he called the name of the first daughter Jemimah, and the name of the second Keziah, and the name of the third Keren-happuch.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":14},{"ref":"Job 42:15","short":"Job 42:15","text":"And in all the land there were no women so beautiful as Job\u2019s daughters. And their father gave them an inheritance among their brothers.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":15},{"ref":"Job 42:16","short":"Job 42:16","text":"And after this Job lived 140 years, and saw his sons, and his sons\u2019 sons, four generations.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":16},{"ref":"Job 42:17","short":"Job 42:17","text":"And Job died, an old man, and full of days.","url":"ot/job/Job_42.html","book":"Job","ch":42,"v":17}];
if(!window.VERSES_ALL)window.VERSES_ALL=[];
window.VERSES_ALL=window.VERSES_ALL.concat(VERSES_JOB);
